import { ParsedFilenameResult, DocState } from '../types.ts';

/**
 * Parsea y valida el nombre de archivo según la norma institucional estricta.
 * Formato esperado: PROYECTO - Microproceso - TIPO - Versión
 * Ejemplo: HPC - Gestión de Proyectos - ASIS - v1.0
 */
export const parseDocumentFilename = (
  fullFilename: string, 
  expectedProject?: string,
  expectedMicro?: string,
  expectedType?: string,
  expectedRequestType?: 'INITIATED' | 'IN_PROCESS' | 'INTERNAL' | 'REFERENT' | 'CONTROL'
): ParsedFilenameResult => {
  const result: ParsedFilenameResult = {
    valido: false,
    errores: []
  };

  // 1. Separar nombre de extensión
  const lastDotIndex = fullFilename.lastIndexOf('.');
  const filenameBase = lastDotIndex !== -1 ? fullFilename.substring(0, lastDotIndex) : fullFilename;

  // 2. Validar longitud máxima (80 caracteres)
  if (filenameBase.length > 80) {
    result.errores.push(`El nombre del archivo excede 80 caracteres.`);
  }

  // 3. Validar Estructura General
  const parts = filenameBase.split(' - ');

  if (parts.length < 4) {
    result.errores.push('Formato incorrecto. Use: "PROYECTO - Microproceso - TIPO - Versión".');
    return result;
  }

  const proyecto = parts[0];
  const version = parts[parts.length - 1];
  const tipoCodigo = parts[parts.length - 2];
  const microproceso = parts.slice(1, parts.length - 2).join(' - ');

  // 4. Validar Proyecto
  if (proyecto !== 'HPC' && proyecto !== 'HSR') {
    result.errores.push(`Proyecto inválido: ${proyecto}.`);
  } else if (expectedProject && proyecto !== expectedProject) {
    result.errores.push(`Proyecto no coincide con la solicitud.`);
  }
  result.proyecto = proyecto as 'HPC' | 'HSR';

  // 5. Validar Microproceso
  if (!microproceso || microproceso.trim() === '') {
    result.errores.push('Microproceso vacío.');
  } else if (expectedMicro && microproceso !== expectedMicro) {
    result.errores.push(`Microproceso no coincide.`);
  }
  result.microproceso = microproceso;

  // 6. Validar Tipo
  const mapTypeToCode: Record<string, string> = {
      'AS IS': 'ASIS', 'TO BE': 'TOBE', 'FCE': 'FCE', 'PM': 'PM'
  };
  const validCodes = Object.values(mapTypeToCode);
  if (!validCodes.includes(tipoCodigo)) {
      result.errores.push(`Tipo inválido: ${tipoCodigo}.`);
  }
  if (expectedType) {
      const expectedCode = mapTypeToCode[expectedType];
      if (tipoCodigo !== expectedCode) {
          result.errores.push(`Tipo no coincide con la solicitud.`);
      }
  }
  result.tipo = tipoCodigo;

  // 7. Analizar Versión y Reglas de Solicitud
  result.nomenclatura = version;

  // Regex básicos
  const regexInitiated = /^0\.0$/;              // 0.0 (Estricto)
  const regexInProcess = /^0\.(\d+)$/;          // 0.n (Sin 'v', n > 0)
  const regexInternal = /^v0\.(\d+)$/;          // v0.n (Con 'v', impar)
  const regexReferent = /^v1\.(\d+)\.(\d+)$/;   // v1.n.i
  const regexControl = /^v1\.(\d+)\.(\d+)AR$/;  // v1.n.iAR
  const regexStandard = /^v?\d+(\.\d+)*([A-Z]+)?$/;

  if (expectedRequestType) {
      if (expectedRequestType === 'INITIATED') {
          if (!regexInitiated.test(version)) {
              result.errores.push('Para estado "Iniciado" la versión debe ser estrictamente "0.0".');
          }
      } else if (expectedRequestType === 'IN_PROCESS') {
          const match = version.match(regexInProcess);
          if (!match) {
              result.errores.push('Para "En Proceso" el formato debe ser "0.n" (ej: 0.1, 0.2) sin la letra "v".');
          } else {
               const n = parseInt(match[1]);
               if (n === 0) {
                   result.errores.push('La versión 0.0 corresponde a "Iniciado". Para "En Proceso" n debe ser mayor a 0 (ej: 0.1).');
               }
          }
      } else if (expectedRequestType === 'INTERNAL') {
          const match = version.match(regexInternal);
          if (!match) {
              result.errores.push('Para Revisión Interna el formato debe ser "v0.n" (con v).');
          } else {
              const n = parseInt(match[1]);
              if (n % 2 === 0) {
                  result.errores.push(`Para Revisión Interna el dígito "n" (${n}) debe ser IMPAR (ej: v0.1, v0.3).`);
              }
          }
      } else if (expectedRequestType === 'REFERENT') {
          const match = version.match(regexReferent);
          if (!match) {
              result.errores.push('Para Revisión Interna Referente el formato debe ser "v1.n.i" (ej: v1.0.1).');
          } else {
              const i = parseInt(match[2]);
              if (i % 2 === 0) {
                  result.errores.push(`Para Revisión Interna Referente el dígito "i" (${i}) debe ser IMPAR (ej: v1.0.1, v1.0.3).`);
              }
          }
      } else if (expectedRequestType === 'CONTROL') {
          const match = version.match(regexControl);
          if (!match) {
              result.errores.push('Para Revisión Interna Control el formato debe ser "v1.n.iAR" (ej: v1.0.1AR).');
          } else {
              const i = parseInt(match[2]);
              if (i % 2 === 0) {
                  result.errores.push(`Para Revisión Interna Control el dígito "i" (${i}) debe ser IMPAR (ej: v1.0.1AR).`);
              }
          }
      }
  } else {
      // Validación genérica si no hay tipo de solicitud explícito
      if (!regexStandard.test(version)) {
          // Intentamos ser permisivos con 0.0 y 0.n si no hay expectedType pero validamos formato general
          if (!regexInitiated.test(version) && !regexInProcess.test(version)) {
             result.errores.push(`Formato de versión inválido: ${version}`);
          }
      }
  }

  // Logic map for state detection (Auto-detect if not enforced)
  // IMPROVED LOGIC FOR INTERMEDIATE STATES
  if (result.errores.length === 0) {
      if (version.endsWith('ACG')) {
          result.estado = 'Aprobado';
          result.porcentaje = 100;
      } else if (version.endsWith('AR')) {
          // v1.nAR vs v1.n.iAR
          if (version.match(/^v1\.(\d+)\.(\d+)AR$/)) {
              result.estado = 'Revisión Interna Control'; // Intermediate
              result.porcentaje = 90;
          } else {
              result.estado = 'Enviado a Control de Gestión'; // v1.nAR
              result.porcentaje = 90;
          }
      } else if (version.startsWith('v1.')) {
          // v1.n vs v1.n.i
          if (version.split('.').length > 2) {
              result.estado = 'Revisión Interna Referente'; // v1.n.i
              result.porcentaje = 80;
          } else {
              result.estado = 'Enviado a Referente'; // v1.n
              result.porcentaje = 80;
          }
      } else if (version.startsWith('v0.')) {
          result.estado = 'En revisión interna'; 
          result.porcentaje = 60;
      } else if (version === '0.0') {
          result.estado = 'Iniciado';
          result.porcentaje = 10;
      } else if (/^0\.\d+$/.test(version)) {
          result.estado = 'En Proceso';
          result.porcentaje = 30;
      } else {
          result.estado = 'En Proceso'; 
          result.porcentaje = 30;
      }
  }

  result.valido = result.errores.length === 0;
  return result;
};

/**
 * Valida las reglas de transición de versiones para el COORDINADOR (Aprobar/Rechazar).
 */
export const validateCoordinatorRules = (
    filename: string,
    currentVersion: string, 
    currentState: DocState,
    action: 'APPROVE' | 'REJECT'
): { valid: boolean; error?: string; hint?: string } => {

    // Parse parts
    const parts = filename.replace(/\.[^/.]+$/, "").split(' - ');
    if (parts.length < 4) return { valid: false, error: 'Formato de nombre inválido.' };
    const newVersion = parts[parts.length - 1];

    // Helper to decompose version into components
    const getParts = (v: string) => {
        let m;
        // v0.n (Internal Request or Reject Internal)
        m = v.match(/^v?0\.(\d+)$/);
        if (m) return { n: parseInt(m[1]), i: null, ar: false, acg: false, type: 'v0.n' };

        // v1.n (Internal Approve or Referent Approve)
        m = v.match(/^v1\.(\d+)$/);
        if (m) return { n: parseInt(m[1]), i: null, ar: false, acg: false, type: 'v1.n' };

        // v1.n.i (Referent Request OR Referent Reject)
        m = v.match(/^v1\.(\d+)\.(\d+)$/);
        if (m) return { n: parseInt(m[1]), i: parseInt(m[2]), ar: false, acg: false, type: 'v1.n.i' };

        // v1.n.iAR (Control Request OR Control Reject)
        m = v.match(/^v1\.(\d+)\.(\d+)AR$/);
        if (m) return { n: parseInt(m[1]), i: parseInt(m[2]), ar: true, acg: false, type: 'v1.n.iAR' };

        // v1.nAR (Control Approve / Version Advance)
        m = v.match(/^v1\.(\d+)AR$/);
        if (m) return { n: parseInt(m[1]), i: null, ar: true, acg: false, type: 'v1.nAR' };

        // v1.nACG (Final Approval)
        m = v.match(/^v1\.(\d+)ACG$/);
        if (m) return { n: parseInt(m[1]), i: null, ar: false, acg: true, type: 'v1.nACG' };

        return null;
    };

    const current = getParts(currentVersion);
    const incoming = getParts(newVersion);

    if (!incoming) return { valid: false, error: 'Formato de versión no reconocido.' };

    // =========================================================
    // ETAPA 1: REVISIÓN INTERNA (v0.x)
    // =========================================================
    if (currentState === DocState.INTERNAL_REVIEW) {
        if (action === 'APPROVE') {
            // Aprobar revisión interna: subir v1.n (entero)
            if (incoming.type !== 'v1.n') return { valid: false, error: 'Aprobación requiere v1.n (Ej: v1.0).' };
            return { valid: true };
        } else {
            // Rechazar revisión interna: subir v0.n (par)
            if (incoming.type !== 'v0.n') return { valid: false, error: 'Rechazo requiere v0.n.' };
            if (incoming.n % 2 !== 0) return { valid: false, error: `Para rechazar, "n" (${incoming.n}) debe ser PAR (ej: v0.2, v0.4).` };
            return { valid: true };
        }
    }

    // =========================================================
    // ETAPA 2: REFERENTE / v1.x (Lógica Avanzada Solicitada)
    // =========================================================
    if (currentState === DocState.SENT_TO_REFERENT || currentState === DocState.REFERENT_REVIEW) {
        if (action === 'APPROVE') {
            // Se permiten dos caminos para aprobar:
            // 1. Consolidación: v1.n (Sin AR) -> Para enviar a referente.
            // 2. Control: v1.nAR (Con AR) -> Para enviar a Control de Gestión.

            if (incoming.type === 'v1.n') {
                // CAMINO 1: Consolidación (v1.0.1 -> v1.1)
                // Regla: n debe ser mayor al actual.
                if (current && incoming.n <= current.n) return { valid: false, error: `Para consolidar versión, v1.${incoming.n} debe ser mayor a la actual (v1.${current.n}...).` };
                return { valid: true };

            } else if (incoming.type === 'v1.nAR') {
                // CAMINO 2: Enviar a Control (AR)

                // Caso A: Vengo de borrador (v1.n.i -> v1.(n+1)AR)
                if (current?.type === 'v1.n.i') {
                    if (incoming.n <= current.n) return { valid: false, error: `Al aprobar borrador para Control, debe consolidar versión (v1.${current.n + 1}AR).` };
                    return { valid: true };
                }

                // Caso B: Vengo de versión limpia (v1.n -> v1.nAR)
                if (current?.type === 'v1.n') {
                    if (incoming.n !== current.n) return { valid: false, error: `Al aprobar versión limpia para Control, mantenga el número (v1.${current.n}AR).` };
                    return { valid: true };
                }

                // Fallback por si el estado actual no coincide con lo esperado
                if (current && incoming.n < current.n) return { valid: false, error: 'No puede bajar de versión.' };
                return { valid: true };

            } else {
                return { valid: false, error: 'Aprobación requiere v1.n (Consolidar) o v1.nAR (Control).' };
            }

        } else {
            // RECHAZAR: v1.n.i (Par y mayor)
            if (incoming.type !== 'v1.n.i') return { valid: false, error: 'Rechazo requiere v1.n.i (Ej: v1.0.2).' };
            if (incoming.i! % 2 !== 0) return { valid: false, error: `Para rechazar, el último dígito "i" (${incoming.i}) debe ser PAR.` };

            // Validar que no baje versión 'n'
            if (current && incoming.n !== current.n) return { valid: false, error: `El rechazo debe mantener la versión base v1.${current.n}.` };
            // Validar que 'i' sea mayor (si venimos de borrador)
            if (current?.i !== null && incoming.i! <= current!.i!) return { valid: false, error: `El dígito "i" (${incoming.i}) debe ser mayor al actual.` };

            return { valid: true };
        }
    }

    // =========================================================
    // ETAPA 3: CONTROL DE GESTIÓN (v1.xAR)
    // =========================================================
    if (currentState === DocState.SENT_TO_CONTROL || currentState === DocState.CONTROL_REVIEW) {
        if (action === 'APPROVE') {
            // Aprobar cambios de versión o final
            if (incoming.type === 'v1.nAR') {
                if (current && incoming.n <= current.n) return { valid: false, error: `Para avanzar versión, v1.${incoming.n}AR debe ser mayor a la actual (v1.${current.n}...).` };
                return { valid: true };
            }
            if (incoming.type === 'v1.nACG') {
                return { valid: true };
            }
            return { valid: false, error: 'Aprobación requiere v1.nAR (avance) o v1.nACG (final).' };
        } else {
            // Rechazar Control: subir v1.n.iAR (i par y mayor al anterior)
            if (incoming.type !== 'v1.n.iAR') return { valid: false, error: 'Rechazo requiere v1.n.iAR (Ej: v1.0.2AR).' };
            if (incoming.i! % 2 !== 0) return { valid: false, error: `Para rechazar, el dígito "i" (${incoming.i}) debe ser PAR.` };

            if (current && current.type === 'v1.n.iAR') {
                 if (incoming.i! <= current.i!) return { valid: false, error: `El dígito "i" (${incoming.i}) debe ser mayor al actual (${current.i}).` };
            }
            return { valid: true };
        }
    }

    // Fallback for other states (not strict)
    return { valid: true };
}

/**
 * Genera el texto de ayuda para el modal
 */
export const getCoordinatorRuleHint = (currentState: DocState, action: 'APPROVE' | 'REJECT'): string => {
    if (action === 'REJECT') {
        if (currentState === DocState.INTERNAL_REVIEW) return 'Formato: v0.n (n PAR). Ej: v0.2';
        if (currentState === DocState.SENT_TO_REFERENT || currentState === DocState.REFERENT_REVIEW) return 'Formato: v1.n.i (i PAR). Ej: v1.0.2';
        if (currentState === DocState.SENT_TO_CONTROL || currentState === DocState.CONTROL_REVIEW) return 'Formato: v1.n.iAR (i PAR y mayor). Ej: v1.0.2AR';
    } else {
        if (currentState === DocState.INTERNAL_REVIEW) return 'Formato: v1.n (Ej: v1.0)';

        if (currentState === DocState.SENT_TO_REFERENT || currentState === DocState.REFERENT_REVIEW) {
            return 'Opción 1: v1.n (Consolidar) / Opción 2: v1.nAR (Enviar a Control)';
        }

        if (currentState === DocState.SENT_TO_CONTROL || currentState === DocState.CONTROL_REVIEW) return 'Opción 1: v1.nAR (Avance) / Opción 2: v1.nACG (Final)';
    }
    return 'Formato estándar';
};

import React, { useState, useEffect } from 'react';
import { HierarchyService, UserService, NotificationService } from '../services/firebaseBackend.ts';
import { User, FullHierarchy, ProcessNode, DocType, UserRole } from '../types.ts';
import { 
  FolderTree, Search, ChevronRight, ChevronDown, Plus, X, Edit, Users, CheckSquare, Square, Filter, RefreshCw, AlertCircle, Link, Layers, Trash2, Loader2
} from 'lucide-react';

interface Props {
  user: User; // Admin User
}

const AdminAssignments: React.FC<Props> = ({ user }) => {
  const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [seeding, setSeeding] = useState(false);

  // State for deletion
  const [hiddenIds, setHiddenIds] = useState<Set<string>>(new Set());
  const [deletingIds, setDeletingIds] = useState<Set<string>>(new Set());

  // Filters State
  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterMicro, setFilterMicro] = useState(''); 
  const [filterAnalyst, setFilterAnalyst] = useState('');

  const [expandedProjects, setExpandedProjects] = useState<Record<string, boolean>>({ 'HPC': true, 'HSR': true });

  // Edit Assignment Modal State
  const [showEditModal, setShowEditModal] = useState(false);
  const [modalProject, setModalProject] = useState('');
  const [modalMacro, setModalMacro] = useState('');
  const [modalProcess, setModalProcess] = useState('');
  const [modalMicro, setModalMicro] = useState('');
  const [currentAssignees, setCurrentAssignees] = useState<string[]>([]);
  const [originalAssignees, setOriginalAssignees] = useState<string[]>([]);
  const [matrixKeyToUpdate, setMatrixKeyToUpdate] = useState<string | null>(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async (showLoader = true) => {
    if (showLoader) setLoading(true);
    try {
        const [h, u] = await Promise.all([
          HierarchyService.getFullHierarchy(),
          UserService.getAll()
        ]);
        setHierarchy(h);
        setAllUsers(u);
    } catch (e) {
        console.error("Error loading assignments data:", e);
    } finally {
        if (showLoader) setLoading(false);
    }
  };

  const handleSeedDefaults = async () => {
      if (!window.confirm("¿Restaurar configuración de procesos por defecto?\nEsto agregará los microprocesos base si la base de datos está vacía.")) return;
      setSeeding(true);
      try {
          await HierarchyService.seedDefaults();
          await loadData();
          alert("Datos restaurados correctamente.");
      } catch (e: any) {
          alert("Error: " + e.message);
      } finally {
          setSeeding(false);
      }
  };

  const toggleProject = (proj: string) => {
    setExpandedProjects(prev => ({ ...prev, [proj]: !prev[proj] }));
  };

  // --- DELETE HANDLER (Matching Production Message) ---
  const handleDelete = async (project: string, macro: string, process: string, id: string, microName: string, e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();

      const cleanId = id?.trim();
      if (!cleanId) return;

      // MENSAJE EXACTO DE LA CAPTURA DE PANTALLA
      const confirmMsg = `¿Estás seguro de que deseas eliminar el microproceso "${microName}" de la matriz?\nEsta acción es irreversible en esta vista.`;

      if(!window.confirm(confirmMsg)) return;

      // 1. Ocultar inmediatamente (Visual)
      setHiddenIds(prev => new Set(prev).add(cleanId));
      setDeletingIds(prev => new Set(prev).add(cleanId)); 

      // 2. ELIMINAR DEL ESTADO LOCAL
      setHierarchy(prev => {
          const next = { ...prev };
          if (next[project] && next[project][macro] && next[project][macro][process]) {
              next[project][macro][process] = next[project][macro][process].filter(node => node.docId !== cleanId);
          }
          return next;
      });

      try {
          await HierarchyService.deleteMicroprocess(cleanId);
      } catch (e: any) {
          console.error("Error API:", e);
          alert("Error en el servidor, pero se ha ocultado localmente: " + e.message);
      } finally {
          setDeletingIds(prev => {
              const next = new Set(prev);
              next.delete(cleanId);
              return next;
          });
      }
  };

  // --- Handlers for EDIT Modal ---
  const handleEditAssignment = (
      proj: string, macro: string, proc: string, microObj: ProcessNode
  ) => {
      setModalProject(proj);
      setModalMacro(macro);
      setModalProcess(proc);
      setModalMicro(microObj.name);
      setMatrixKeyToUpdate(microObj.docId);
      const existing = [...(microObj.assignees || [])];
      setCurrentAssignees(existing);
      setOriginalAssignees(existing);
      setShowEditModal(true);
  };

  const handleAddAssignee = (userId: string) => {
      if (!userId) return;
      if (!currentAssignees.includes(userId)) {
          setCurrentAssignees([...currentAssignees, userId]);
      }
  };

  const handleRemoveAssignee = (userId: string) => {
      setCurrentAssignees(currentAssignees.filter(id => id !== userId));
  };

  const handleSubmitAssignment = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!matrixKeyToUpdate) return;

      try {
          await HierarchyService.updateMatrixAssignment(matrixKeyToUpdate, currentAssignees);

          const addedAssignees = currentAssignees.filter(id => !originalAssignees.includes(id));
          if (addedAssignees.length > 0) {
              await Promise.all(addedAssignees.map(async (targetId) => {
                  await NotificationService.create(
                      targetId,
                      matrixKeyToUpdate!,
                      'ASSIGNMENT',
                      'Nueva Asignación de Proceso',
                      `Se le ha asignado el proceso: ${modalMicro} (${modalProject})`,
                      user.name
                  );
              }));
          }

          setShowEditModal(false);
          await loadData(false); 
      } catch (err: any) {
          alert(err.message);
      }
  };

  const handleToggleRequiredType = async (matrixKey: string, type: DocType) => {
      await HierarchyService.toggleRequiredType(matrixKey, type);
      await loadData(false);
  };

  // --- Filters Helpers ---
  const getAvailableMacros = () => {
      const macros = new Set<string>();
      Object.keys(hierarchy).forEach(proj => {
          if (filterProject && proj !== filterProject) return;
          Object.keys(hierarchy[proj]).forEach(m => macros.add(m));
      });
      return Array.from(macros).sort();
  };

  const getAvailableProcesses = () => {
      const processes = new Set<string>();
      Object.keys(hierarchy).forEach(proj => {
          if (filterProject && proj !== filterProject) return;
          Object.keys(hierarchy[proj]).forEach(m => {
              if (filterMacro && m !== filterMacro) return;
              Object.keys(hierarchy[proj][m]).forEach(p => processes.add(p));
          });
      });
      return Array.from(processes).sort();
  };

  const clearFilters = () => {
      setFilterProject('');
      setFilterMacro('');
      setFilterProcess('');
      setFilterMicro('');
      setFilterAnalyst('');
  };

  // Flattened Data for Table View within Project
  const getFlattenedRows = (project: string) => {
      const rows: any[] = [];
      const macros = hierarchy[project] || {};

      Object.keys(macros).forEach(macro => {
          if (filterMacro && macro !== filterMacro) return;

          Object.keys(macros[macro]).forEach(proc => {
              if (filterProcess && proc !== filterProcess) return;

              const nodes = macros[macro][proc];
              nodes.forEach(node => {
                  if (hiddenIds.has(node.docId)) return; // Skip deleted locally

                  // IMPORTANT: Filter out inactive nodes (Soft Deleted in Hierarchy)
                  // This ensures consistency between views.
                  if (node.active === false) return; 

                  if (filterMicro && !node.name.toLowerCase().includes(filterMicro.toLowerCase())) return;
                  if (filterAnalyst && (!node.assignees || !node.assignees.includes(filterAnalyst))) return;
                  rows.push({ macro, proc, node });
              });
          });
      });
      return rows;
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando matriz de procesos...</div>;

  const hasActiveFilters = filterProject || filterMacro || filterProcess || filterMicro || filterAnalyst;
  const isHierarchyEmpty = Object.keys(hierarchy).length === 0;

  return (
    <div className="space-y-6 pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Gestor de Asignaciones</h1>
          <p className="text-slate-500">Asigne analistas responsables y defina documentos requeridos.</p>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
             {isHierarchyEmpty && (
                 <button 
                    onClick={handleSeedDefaults}
                    disabled={seeding}
                    className="flex items-center px-4 py-2 bg-yellow-50 text-yellow-700 border border-yellow-200 rounded-lg hover:bg-yellow-100 transition-colors shadow-sm font-medium whitespace-nowrap"
                >
                    <RefreshCw size={18} className={`mr-2 ${seeding ? 'animate-spin' : ''}`} />
                    {seeding ? 'Restaurando...' : 'Cargar Datos por Defecto'}
                </button>
             )}
        </div>
      </div>

      {/* FILTER BAR */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
          <div className="flex items-center justify-between mb-3 border-b border-slate-100 pb-2">
              <h3 className="font-semibold text-slate-700 flex items-center gap-2">
                  <Filter size={18} className="text-indigo-600" /> Filtros de Matriz
              </h3>
              {hasActiveFilters && (
                  <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1">
                      <X size={14} /> Limpiar Todo
                  </button>
              )}
          </div>
          <div className="grid grid-cols-1 md:grid-cols-5 gap-3">
              <select 
                  value={filterProject} 
                  onChange={(e) => setFilterProject(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Proyecto (Todos)</option>
                  {Object.keys(hierarchy).map(p => <option key={p} value={p}>{p}</option>)}
              </select>

              <select 
                  value={filterMacro} 
                  onChange={(e) => setFilterMacro(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Macroproceso (Todos)</option>
                  {getAvailableMacros().map(m => <option key={m} value={m}>{m}</option>)}
              </select>

              <select 
                  value={filterProcess} 
                  onChange={(e) => setFilterProcess(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Proceso (Todos)</option>
                  {getAvailableProcesses().map(p => <option key={p} value={p}>{p}</option>)}
              </select>

              <div className="relative">
                  <Search size={16} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" />
                  <input 
                      type="text" 
                      placeholder="Buscar Microproceso..."
                      value={filterMicro}
                      onChange={(e) => setFilterMicro(e.target.value)}
                      className="w-full pl-8 p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
              </div>

               <select 
                  value={filterAnalyst} 
                  onChange={(e) => setFilterAnalyst(e.target.value)}
                  className="p-2 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              >
                  <option value="">Analista (Todos)</option>
                  {allUsers
                    .filter(u => u.role === UserRole.ANALYST) // Strict Filter
                    .map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
              </select>
          </div>
      </div>

      {isHierarchyEmpty && (
          <div className="p-8 bg-slate-50 border border-slate-200 rounded-xl text-center">
              <Layers size={48} className="mx-auto text-slate-300 mb-3" />
              <h3 className="text-lg font-bold text-slate-700">La Matriz de Procesos está vacía</h3>
              <p className="text-slate-500 mb-4">No se han definido procesos ni asignaciones aún.</p>
              <button 
                onClick={handleSeedDefaults}
                disabled={seeding}
                className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-sm font-medium"
              >
                  Cargar Datos por Defecto
              </button>
          </div>
      )}

      <div className="space-y-4">
        {Object.keys(hierarchy).map(projectKey => {
            if (filterProject && projectKey !== filterProject) return null;

            const rows = getFlattenedRows(projectKey);
            if (rows.length === 0) return null;

            return (
                <div key={projectKey} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                    {/* Project Header */}
                    <div 
                        onClick={() => toggleProject(projectKey)}
                        className="flex items-center justify-between p-4 bg-slate-50 hover:bg-slate-100 cursor-pointer transition-colors border-b border-slate-200"
                    >
                        <div className="flex items-center gap-2 font-bold text-slate-800 text-lg">
                            {expandedProjects[projectKey] ? <ChevronDown size={20} /> : <ChevronRight size={20} />}
                            <FolderTree size={20} className="text-indigo-600" />
                            Proyecto {projectKey}
                        </div>
                        <span className="text-xs text-slate-500 font-medium bg-white px-2 py-1 rounded border border-slate-200">
                            {rows.length} Microprocesos
                        </span>
                    </div>

                    {/* Table View */}
                    {expandedProjects[projectKey] && (
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm text-left">
                                <thead className="text-xs text-slate-500 uppercase bg-slate-50/50">
                                    <tr>
                                        <th className="px-4 py-3 w-1/4">Jerarquía (Macro / Proceso)</th>
                                        <th className="px-4 py-3 w-1/4">Microproceso</th>
                                        <th className="px-4 py-3 w-1/5">Documentos Definidos</th>
                                        <th className="px-4 py-3 w-1/4">Analistas Responsables</th>
                                        <th className="px-4 py-3 text-right">Acciones</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100">
                                    {rows.map((row, idx) => (
                                        <tr key={`${row.node.docId}-${idx}`} className="hover:bg-slate-50 transition-colors">
                                            {/* Jerarquía */}
                                            <td className="px-4 py-3 align-top text-slate-600">
                                                <div className="font-semibold text-xs text-slate-700 mb-0.5">{row.macro}</div>
                                                <div className="text-xs text-slate-500 pl-2 border-l-2 border-slate-200">{row.proc}</div>
                                            </td>

                                            {/* Microproceso */}
                                            <td className="px-4 py-3 align-top">
                                                <span className="font-medium text-slate-900">{row.node.name}</span>
                                            </td>

                                            {/* Documentos Checkboxes */}
                                            <td className="px-4 py-3 align-top">
                                                <div className="flex items-center gap-2 flex-wrap">
                                                    {['AS IS', 'FCE', 'PM', 'TO BE'].map((type) => {
                                                        const isChecked = row.node.requiredTypes && row.node.requiredTypes.includes(type as DocType);
                                                        return (
                                                            <button 
                                                                key={type}
                                                                onClick={() => handleToggleRequiredType(row.node.docId, type as DocType)}
                                                                className={`flex items-center gap-1 px-1.5 py-0.5 rounded text-[10px] font-bold border transition-all ${
                                                                    isChecked 
                                                                    ? 'bg-indigo-100 text-indigo-700 border-indigo-200 hover:bg-indigo-200' 
                                                                    : 'bg-slate-50 text-slate-300 border-slate-200 hover:border-slate-300'
                                                                }`}
                                                                title={`Alternar ${type}`}
                                                            >
                                                                {isChecked ? <CheckSquare size={10} /> : <Square size={10} />}
                                                                {type}
                                                            </button>
                                                        );
                                                    })}
                                                </div>
                                            </td>

                                            {/* Analistas */}
                                            <td className="px-4 py-3 align-top">
                                                {(row.node.assignees && row.node.assignees.length > 0) ? (
                                                    <>
                                                        <div className="flex -space-x-2 overflow-hidden py-1">
                                                            {row.node.assignees.map((aid: string) => {
                                                                const u = allUsers.find(user => user.id === aid);
                                                                if (!u) {
                                                                    return (
                                                                         <div key={aid} className="inline-flex h-6 w-6 items-center justify-center rounded-full ring-2 ring-white bg-slate-200 text-[10px] text-slate-500 font-bold cursor-help" title={`Usuario ID: ${aid} no encontrado`}>?</div>
                                                                    );
                                                                }
                                                                return (
                                                                    <div key={u.id} className="inline-block h-6 w-6 rounded-full ring-2 ring-white bg-indigo-100 overflow-hidden" title={u.name}>
                                                                        {u.avatar ? <img src={u.avatar} className="h-full w-full object-cover" /> : <span className="flex h-full w-full items-center justify-center text-[10px] font-bold text-indigo-700">{u.name.charAt(0)}</span>}
                                                                    </div>
                                                                );
                                                            })}
                                                        </div>
                                                        <div className="text-xs text-slate-500 mt-1 truncate">
                                                             {row.node.assignees.map((aid: string) => {
                                                                 const u = allUsers.find(user => user.id === aid);
                                                                 return u ? u.name : 'Desconocido';
                                                             }).join(', ')}
                                                        </div>
                                                    </>
                                                ) : (
                                                    <span className="text-xs text-red-400 italic py-1 block">Sin asignar</span>
                                                )}
                                            </td>

                                            {/* Acciones */}
                                            <td className="px-4 py-3 align-top text-right">
                                                <div className="flex justify-end gap-1">
                                                    <button 
                                                        onClick={() => handleEditAssignment(projectKey, row.macro, row.proc, row.node)}
                                                        className="text-slate-400 hover:text-indigo-600 p-1.5 hover:bg-indigo-50 rounded transition-colors"
                                                        title="Editar Asignación"
                                                    >
                                                        <Users size={16} />
                                                    </button>
                                                    {/* Botón de Eliminar Restaurado */}
                                                    <button 
                                                        onClick={(e) => handleDelete(projectKey, row.macro, row.proc, row.node.docId, row.node.name, e)}
                                                        className="text-slate-400 hover:text-red-600 p-1.5 hover:bg-red-50 rounded transition-colors"
                                                        title="Eliminar Microproceso"
                                                        disabled={deletingIds.has(row.node.docId?.trim())}
                                                    >
                                                        {deletingIds.has(row.node.docId?.trim()) ? (
                                                            <Loader2 size={16} className="animate-spin text-red-600" />
                                                        ) : (
                                                            <Trash2 size={16} />
                                                        )}
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    ))}
                                    {rows.length === 0 && (
                                        <tr><td colSpan={5} className="p-4 text-center text-slate-400 text-sm">No se encontraron resultados en este proyecto.</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
            );
        })}
      </div>

      {/* MODAL 1: EDIT ASSIGNMENT */}
      {showEditModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
                <div className="p-5 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
                    <h3 className="text-lg font-bold text-slate-800">Editar Asignación</h3>
                    <button onClick={() => setShowEditModal(false)} className="text-slate-400 hover:text-slate-600"><X size={20} /></button>
                </div>

                <form onSubmit={handleSubmitAssignment} className="p-6">
                    <div className="mb-6 bg-indigo-50/50 p-4 rounded-lg border border-indigo-100 text-sm">
                        <div className="grid grid-cols-3 gap-y-2">
                             <span className="text-slate-500">Proyecto:</span> <span className="col-span-2 font-medium">{modalProject}</span>
                             <span className="text-slate-500">Proceso:</span> <span className="col-span-2 font-medium">{modalProcess}</span>
                             <span className="text-slate-500 font-bold">Microproceso:</span> <span className="col-span-2 font-bold text-indigo-700">{modalMicro}</span>
                        </div>
                    </div>

                    <div className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">Analistas Asignados</label>
                            <div className="space-y-2 max-h-40 overflow-y-auto border border-slate-200 rounded-lg p-2">
                                {currentAssignees.length === 0 ? (
                                    <p className="text-sm text-slate-400 italic text-center py-2">No hay analistas asignados.</p>
                                ) : (
                                    currentAssignees.map(aid => {
                                        const u = allUsers.find(user => user.id === aid);
                                        return (
                                            <div key={aid} className="flex items-center justify-between p-2 bg-slate-50 rounded border border-slate-100">
                                                <div className="flex items-center gap-2">
                                                    {u && (u.avatar ? <img src={u.avatar} className="w-6 h-6 rounded-full" /> : <div className="w-6 h-6 rounded-full bg-indigo-100 flex items-center justify-center text-xs text-indigo-700 font-bold">{u.name.charAt(0)}</div>)}
                                                    <span className="text-sm font-medium text-slate-700">{u ? u.name : `Usuario Eliminado (${aid})`}</span>
                                                </div>
                                                <button type="button" onClick={() => handleRemoveAssignee(aid)} className="text-red-400 hover:text-red-600">
                                                    <X size={16} />
                                                </button>
                                            </div>
                                        );
                                    })
                                )}
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Agregar Analista</label>
                            <select 
                                className="w-full p-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                                onChange={(e) => handleAddAssignee(e.target.value)}
                                value=""
                            >
                                <option value="">Seleccionar analista para agregar...</option>
                                {allUsers
                                    .filter(u => u.role === UserRole.ANALYST && !currentAssignees.includes(u.id)) // Strict Filter + Exclusion
                                    .map(u => (
                                        <option key={u.id} value={u.id}>{u.name}</option>
                                ))}
                            </select>
                        </div>
                    </div>

                    <div className="flex justify-end pt-6 gap-3">
                        <button 
                            type="button" 
                            onClick={() => setShowEditModal(false)}
                            className="px-4 py-2 text-slate-600 hover:text-slate-800 text-sm font-medium"
                        >
                            Cancelar
                        </button>
                        <button 
                            type="submit"
                            className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium shadow-sm"
                        >
                            Guardar Cambios
                        </button>
                    </div>
                </form>
            </div>
          </div>
      )}
    </div>
  );
};

export default AdminAssignments;

import React, { useState, useEffect, useMemo } from 'react';
import { HierarchyService, generateMatrixId } from '../services/firebaseBackend.ts';
import { FullHierarchy, ProcessNode, User, UserRole } from '../types.ts';
import { 
  FolderTree, ChevronRight, ChevronDown, Plus, X, Edit, Trash2, Save, Layers, Network, FolderOpen, FileText, Loader2, Search, Eye, EyeOff, Power, FolderInput, ArrowRight, AlertTriangle
} from 'lucide-react';

interface Props {
    user: User;
}

const AdminHierarchy: React.FC<Props> = ({ user }) => {
  const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
  const [loading, setLoading] = useState(true);

  // Selection State
  const [selectedProject, setSelectedProject] = useState<string | null>(null);
  const [selectedMacro, setSelectedMacro] = useState<string | null>(null);
  const [selectedProcess, setSelectedProcess] = useState<string | null>(null);

  // Search State
  const [searchTerm, setSearchTerm] = useState('');

  // View Options
  const [showInactive, setShowInactive] = useState(false);

  // Modal State
  const [showAddModal, setShowAddModal] = useState(false);
  const [addLevel, setAddLevel] = useState<'PROJECT' | 'MACRO' | 'PROCESS' | 'MICRO'>('PROJECT');
  const [newItemName, setNewItemName] = useState('');

  // Rename State
  const [renameMode, setRenameMode] = useState<{ level: string, oldName: string } | null>(null);
  const [renameValue, setRenameValue] = useState('');

  // Move Modal State
  const [showMoveModal, setShowMoveModal] = useState(false);
  const [moveTarget, setMoveTarget] = useState<{ docId: string, name: string, currentProject: string, currentMacro: string, currentProcess: string } | null>(null);
  const [targetProject, setTargetProject] = useState('');
  const [targetMacro, setTargetMacro] = useState('');
  const [targetProcess, setTargetProcess] = useState('');

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
        const h = await HierarchyService.getFullHierarchy();
        setHierarchy(h);
    } catch (e) {
        console.error("Error loading hierarchy:", e);
    } finally {
        setLoading(false);
    }
  };

  // --- ACTIONS ---

  const handleAdd = (level: 'PROJECT' | 'MACRO' | 'PROCESS' | 'MICRO') => {
      setAddLevel(level);
      setNewItemName('');
      setShowAddModal(true);
  };

  const handleCreateSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!newItemName.trim()) return;

      try {
          let project = selectedProject || newItemName;
          let macro = selectedMacro || (addLevel === 'PROJECT' ? 'General' : newItemName);
          let process = selectedProcess || ((addLevel === 'PROJECT' || addLevel === 'MACRO') ? 'General' : newItemName);
          let micro = (addLevel === 'MICRO') ? newItemName : 'Inicio';

          if (addLevel === 'PROJECT') project = newItemName;
          if (addLevel === 'MACRO') macro = newItemName;
          if (addLevel === 'PROCESS') process = newItemName;

          await HierarchyService.addMicroprocess(project, macro, process, micro, [], ['AS IS', 'FCE', 'PM', 'TO BE']);

          setShowAddModal(false);
          await loadData();

          if (addLevel === 'PROJECT') setSelectedProject(newItemName);
          if (addLevel === 'MACRO') setSelectedMacro(newItemName);
          if (addLevel === 'PROCESS') setSelectedProcess(newItemName);

      } catch (err: any) {
          alert('Error: ' + err.message);
      }
  };

  const handleToggleStatus = async (id: string, name: string, currentStatus: boolean, e: React.MouseEvent) => {
      e.stopPropagation();
      // Soft delete confirmation
      const action = currentStatus ? "Inactivar" : "Reactivar";
      const confirmMsg = currentStatus 
        ? `¿Inactivar microproceso "${name}"?\nDejará de estar disponible para nuevos documentos, pero se conservará el historial.`
        : `¿Reactivar microproceso "${name}"?`;

      if (!window.confirm(confirmMsg)) return;

      try {
          await HierarchyService.toggleProcessStatus(id, currentStatus);
          await loadData(); // Reload to reflect changes
      } catch (e: any) {
          alert(`Error al ${action.toLowerCase()}: ` + e.message);
      }
  };

  // --- HARD DELETE MICROPROCESS (ADMIN ONLY) ---
  const handleHardDeleteMicro = async (id: string, name: string, e: React.MouseEvent) => {
      e.stopPropagation();

      const confirmMsg = `⚠️ PELIGRO: Eliminación Permanente ⚠️\n\n¿Estás seguro de que deseas ELIMINAR definitivamente el microproceso "${name}"?\n\nEsta acción borrará el nodo de la estructura y romperá la relación con los documentos existentes.`;

      if (!window.confirm(confirmMsg)) return;

      // OPTIMISTIC UPDATE: Remove from UI immediately
      setHierarchy(prev => {
          const next = { ...prev };
          // Deep traversal to find and remove the node in local state
          Object.keys(next).forEach(proj => {
              Object.keys(next[proj]).forEach(macro => {
                  Object.keys(next[proj][macro]).forEach(proc => {
                      next[proj][macro][proc] = next[proj][macro][proc].filter(n => n.docId !== id);
                  });
              });
          });
          return next;
      });

      try {
          // No global loading spinner to keep the UI fluid, the item is already gone
          await HierarchyService.deleteMicroprocess(id);
          // Background sync to ensure consistency
          setTimeout(loadData, 500); 
      } catch (e: any) {
          alert("Error al eliminar: " + e.message);
          loadData(); // Revert on error
      }
  };

  // NEW: Delete logic for parent nodes
  const handleDeleteNode = async (level: 'PROJECT' | 'MACRO' | 'PROCESS', name: string, e: React.MouseEvent) => {
      e.stopPropagation();

      // Additional safety check on frontend
      if (user.role !== UserRole.ADMIN) {
          alert("Acción no permitida. Solo administradores.");
          return;
      }

      const warningMsg = `⚠️ ADVERTENCIA CRÍTICA ⚠️\n\nEstá a punto de eliminar el ${level}: "${name}".\n\nEsta acción ELIMINARÁ TODOS los datos contenidos en él (Macroprocesos, Procesos y Microprocesos). \n\n¿Está absolutamente seguro?`;

      if (!window.confirm(warningMsg)) return;

      try {
          setLoading(true);
          const parentContext = {
              project: selectedProject || undefined,
              macro: selectedMacro || undefined
          };

          await HierarchyService.deleteHierarchyNode(level, name, parentContext);

          // Clear selections if deleted
          if (level === 'PROJECT' && selectedProject === name) { setSelectedProject(null); setSelectedMacro(null); setSelectedProcess(null); }
          if (level === 'MACRO' && selectedMacro === name) { setSelectedMacro(null); setSelectedProcess(null); }
          if (level === 'PROCESS' && selectedProcess === name) { setSelectedProcess(null); }

          await loadData();
      } catch (err: any) {
          alert("Error al eliminar: " + err.message);
          setLoading(false);
      }
  };

  const handleRenameStart = (level: 'PROJECT' | 'MACRO' | 'PROCESS', oldName: string) => {
      setRenameMode({ level, oldName });
      setRenameValue(oldName);
  };

  const handleRenameSubmit = async () => {
      if (!renameMode || !renameValue.trim() || renameValue === renameMode.oldName) {
          setRenameMode(null);
          return;
      }

      if (!window.confirm(`¿Renombrar "${renameMode.oldName}" a "${renameValue}"?\nEsto actualizará TODOS los microprocesos contenidos en esta carpeta.`)) return;

      try {
          setLoading(true);
          const parentContext = {
              project: selectedProject || undefined,
              macro: selectedMacro || undefined
          };

          await HierarchyService.updateHierarchyNode(
              renameMode.level as any, 
              renameMode.oldName, 
              renameValue, 
              parentContext
          );

          if (renameMode.level === 'PROJECT' && selectedProject === renameMode.oldName) setSelectedProject(renameValue);
          if (renameMode.level === 'MACRO' && selectedMacro === renameMode.oldName) setSelectedMacro(renameValue);
          if (renameMode.level === 'PROCESS' && selectedProcess === renameMode.oldName) setSelectedProcess(renameValue);

          setRenameMode(null);
          await loadData();
      } catch (e: any) {
          alert('Error al renombrar: ' + e.message);
          setLoading(false);
      }
  };

  // --- MOVE / RELOCATE LOGIC ---
  const handleMoveStart = (micro: ProcessNode, e: React.MouseEvent) => {
      e.stopPropagation();
      setMoveTarget({
          docId: micro.docId,
          name: micro.name,
          currentProject: selectedProject || '',
          currentMacro: selectedMacro || '',
          currentProcess: selectedProcess || ''
      });
      // Pre-fill current values or defaults
      setTargetProject(selectedProject || '');
      setTargetMacro(selectedMacro || '');
      setTargetProcess(selectedProcess || '');
      setShowMoveModal(true);
  };

  const handleMoveSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!moveTarget || !targetProject || !targetMacro || !targetProcess) return;

      // Verification
      if (targetProject === moveTarget.currentProject && targetMacro === moveTarget.currentMacro && targetProcess === moveTarget.currentProcess) {
          alert("El destino es el mismo que el origen. No se realizaron cambios.");
          setShowMoveModal(false);
          return;
      }

      try {
          setLoading(true);
          await HierarchyService.moveMicroprocess(moveTarget.docId, targetProject, targetMacro, targetProcess);
          setShowMoveModal(false);
          await loadData();
      } catch (err: any) {
          alert('Error al reubicar: ' + err.message);
      } finally {
          setLoading(false);
      }
  };

  // --- MEMOIZED FLATTENED LIST FOR SEARCH ---
  const flatNodes = useMemo(() => {
      const list: { 
          project: string, macro: string, process: string, micro: ProcessNode, path: string 
      }[] = [];

      Object.keys(hierarchy).forEach(proj => {
          Object.keys(hierarchy[proj]).forEach(macro => {
              Object.keys(hierarchy[proj][macro]).forEach(proc => {
                  hierarchy[proj][macro][proc].forEach(node => {
                      if (!showInactive && node.active === false) return;
                      list.push({
                          project: proj,
                          macro: macro,
                          process: proc,
                          micro: node,
                          path: `${proj} > ${macro} > ${proc} > ${node.name}`
                      });
                  });
              });
          });
      });
      return list;
  }, [hierarchy, showInactive]);

  const searchResults = useMemo(() => {
      if (!searchTerm) return [];
      const lower = searchTerm.toLowerCase();
      return flatNodes.filter(item => 
          item.path.toLowerCase().includes(lower) || 
          item.micro.name.toLowerCase().includes(lower)
      );
  }, [searchTerm, flatNodes]);


  // --- RENDER HELPERS ---

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Cargando estructura...</div>;

  // Data Pointers (Standard Column View)
  const projects = Object.keys(hierarchy).sort();
  const macros = selectedProject && hierarchy[selectedProject] ? Object.keys(hierarchy[selectedProject]).sort() : [];
  const processes = selectedProject && selectedMacro && hierarchy[selectedProject][selectedMacro] ? Object.keys(hierarchy[selectedProject][selectedMacro]).sort() : [];

  const micros = selectedProject && selectedMacro && selectedProcess && hierarchy[selectedProject][selectedMacro][selectedProcess] 
      ? hierarchy[selectedProject][selectedMacro][selectedProcess] 
      : [];

  // Filter micros for the Column View
  const columnMicros = micros.filter(m => showInactive || m.active !== false);

  // Helper for Move Modal Options
  const availableMacros = targetProject && hierarchy[targetProject] ? Object.keys(hierarchy[targetProject]) : [];
  const availableProcesses = targetProject && targetMacro && hierarchy[targetProject][targetMacro] ? Object.keys(hierarchy[targetProject][targetMacro]) : [];


  return (
    <div className="space-y-6 pb-12">
      <div className="flex flex-col md:flex-row justify-between md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2"><Network className="text-indigo-600" /> Mantenedor de Estructura</h1>
          <p className="text-slate-500">Definición jerárquica de Proyectos, Macros y Procesos.</p>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
            {/* Show Inactive Toggle */}
            <button 
                onClick={() => setShowInactive(!showInactive)}
                className={`flex items-center gap-2 px-3 py-2 rounded-lg text-xs font-bold transition-colors border ${
                    showInactive ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-500 border-slate-300'
                }`}
            >
                {showInactive ? <Eye size={14} /> : <EyeOff size={14} />}
                {showInactive ? 'Ocultar Inactivos' : 'Ver Inactivos'}
            </button>

            {/* SEARCH INPUT */}
            <div className="relative w-full md:w-64">
                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                <input 
                    type="text" 
                    placeholder="Buscar en toda la estructura..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-9 p-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                />
                {searchTerm && (
                    <button 
                        onClick={() => setSearchTerm('')}
                        className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
                    >
                        <X size={14} />
                    </button>
                )}
            </div>
        </div>
      </div>

      {/* CONDITIONAL RENDERING: SEARCH MODE VS COLUMN MODE */}
      {searchTerm ? (
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden min-h-[400px]">
              <div className="p-4 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
                  <h3 className="font-bold text-slate-700">Resultados de Búsqueda</h3>
                  <span className="text-xs text-slate-500">{searchResults.length} coincidencias</span>
              </div>
              <div className="overflow-x-auto">
                  <table className="w-full text-sm text-left">
                      <thead className="text-xs text-slate-500 uppercase bg-slate-50">
                          <tr>
                              <th className="px-4 py-3">Ruta (Breadcrumb)</th>
                              <th className="px-4 py-3">Microproceso</th>
                              <th className="px-4 py-3">Estado</th>
                              <th className="px-4 py-3 text-right">Acciones</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                          {searchResults.map((item) => (
                              <tr key={item.micro.docId} className="hover:bg-slate-50">
                                  <td className="px-4 py-3 text-slate-500">
                                      <div className="flex items-center gap-1 text-xs">
                                          <span className="font-bold text-slate-700">{item.project}</span>
                                          <ChevronRight size={12} />
                                          <span>{item.macro}</span>
                                          <ChevronRight size={12} />
                                          <span>{item.process}</span>
                                      </div>
                                  </td>
                                  <td className="px-4 py-3 font-medium text-slate-800">
                                      {item.micro.name}
                                  </td>
                                  <td className="px-4 py-3">
                                      {item.micro.active !== false ? (
                                          <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-green-100 text-green-700">Activo</span>
                                      ) : (
                                          <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-slate-100 text-slate-500">Inactivo</span>
                                      )}
                                  </td>
                                  <td className="px-4 py-3 text-right flex justify-end gap-1">
                                      <button 
                                          onClick={(e) => handleToggleStatus(item.micro.docId, item.micro.name, item.micro.active !== false, e)} 
                                          className={`p-1.5 rounded transition-colors ${
                                              item.micro.active !== false ? 'text-slate-400 hover:text-red-500 hover:bg-red-50' : 'text-slate-400 hover:text-green-600 hover:bg-green-50'
                                          }`}
                                          title={item.micro.active !== false ? "Inactivar" : "Reactivar"}
                                      >
                                          <Power size={16} />
                                      </button>

                                      {user.role === UserRole.ADMIN && (
                                          <button 
                                              onClick={(e) => handleHardDeleteMicro(item.micro.docId, item.micro.name, e)}
                                              className="p-1.5 rounded text-slate-400 hover:text-red-600 hover:bg-red-50 transition-colors"
                                              title="Eliminar Definitivamente"
                                          >
                                              <Trash2 size={16} />
                                          </button>
                                      )}
                                  </td>
                              </tr>
                          ))}
                          {searchResults.length === 0 && (
                              <tr><td colSpan={4} className="p-8 text-center text-slate-400">No se encontraron resultados para "{searchTerm}"</td></tr>
                          )}
                      </tbody>
                  </table>
              </div>
          </div>
      ) : (
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4 h-[calc(100vh-220px)]">
              {/* STANDARD COLUMN VIEW (SAME AS BEFORE BUT WITH SOFT DELETE BUTTON) */}

              {/* COLUMN 1: PROJECTS */}
              <div className="bg-white rounded-xl shadow-sm border border-slate-200 flex flex-col overflow-hidden">
                  <div className="p-3 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
                      <h3 className="font-bold text-slate-700 text-xs uppercase tracking-wide">Proyectos</h3>
                      <button onClick={() => handleAdd('PROJECT')} className="p-1 hover:bg-indigo-100 text-indigo-600 rounded" title="Nuevo Proyecto"><Plus size={16}/></button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-2 space-y-1">
                      {projects.map(p => (
                          <div 
                            key={p} 
                            onClick={() => { setSelectedProject(p); setSelectedMacro(null); setSelectedProcess(null); }}
                            className={`flex items-center justify-between p-2 rounded-lg cursor-pointer text-sm transition-colors group
                                ${selectedProject === p ? 'bg-indigo-50 text-indigo-700 font-bold' : 'text-slate-600 hover:bg-slate-50'}`}
                          >
                              <div className="flex items-center gap-2 truncate">
                                  <FolderTree size={16} className={selectedProject === p ? 'text-indigo-500' : 'text-slate-400'} />
                                  <span className="truncate">{p}</span>
                              </div>
                              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                  <button onClick={(e) => { e.stopPropagation(); handleRenameStart('PROJECT', p); }} className="text-slate-400 hover:text-indigo-600 p-1"><Edit size={12}/></button>
                                  {user.role === UserRole.ADMIN && (
                                      <button onClick={(e) => handleDeleteNode('PROJECT', p, e)} className="text-slate-400 hover:text-red-600 p-1" title="Eliminar Proyecto"><Trash2 size={12}/></button>
                                  )}
                              </div>
                          </div>
                      ))}
                  </div>
              </div>

              {/* COLUMN 2: MACROS */}
              <div className={`bg-white rounded-xl shadow-sm border border-slate-200 flex flex-col overflow-hidden ${!selectedProject ? 'opacity-50 pointer-events-none' : ''}`}>
                  <div className="p-3 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
                      <h3 className="font-bold text-slate-700 text-xs uppercase tracking-wide">Macroprocesos</h3>
                      {selectedProject && <button onClick={() => handleAdd('MACRO')} className="p-1 hover:bg-indigo-100 text-indigo-600 rounded" title="Nueva Macro"><Plus size={16}/></button>}
                  </div>
                  <div className="flex-1 overflow-y-auto p-2 space-y-1">
                      {macros.length === 0 && <p className="text-xs text-slate-400 text-center py-4 italic">Sin elementos</p>}
                      {macros.map(m => (
                          <div 
                            key={m} 
                            onClick={() => { setSelectedMacro(m); setSelectedProcess(null); }}
                            className={`flex items-center justify-between p-2 rounded-lg cursor-pointer text-sm transition-colors group
                                ${selectedMacro === m ? 'bg-blue-50 text-blue-700 font-bold' : 'text-slate-600 hover:bg-slate-50'}`}
                          >
                              <div className="flex items-center gap-2 truncate">
                                  <FolderOpen size={16} className={selectedMacro === m ? 'text-blue-500' : 'text-slate-400'} />
                                  <span className="truncate">{m}</span>
                              </div>
                              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                  <button onClick={(e) => { e.stopPropagation(); handleRenameStart('MACRO', m); }} className="text-slate-400 hover:text-blue-600 p-1"><Edit size={12}/></button>
                                  {user.role === UserRole.ADMIN && (
                                      <button onClick={(e) => handleDeleteNode('MACRO', m, e)} className="text-slate-400 hover:text-red-600 p-1" title="Eliminar Macro"><Trash2 size={12}/></button>
                                  )}
                              </div>
                          </div>
                      ))}
                  </div>
              </div>

              {/* COLUMN 3: PROCESSES */}
              <div className={`bg-white rounded-xl shadow-sm border border-slate-200 flex flex-col overflow-hidden ${!selectedMacro ? 'opacity-50 pointer-events-none' : ''}`}>
                  <div className="p-3 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
                      <h3 className="font-bold text-slate-700 text-xs uppercase tracking-wide">Procesos</h3>
                      {selectedMacro && <button onClick={() => handleAdd('PROCESS')} className="p-1 hover:bg-indigo-100 text-indigo-600 rounded" title="Nuevo Proceso"><Plus size={16}/></button>}
                  </div>
                  <div className="flex-1 overflow-y-auto p-2 space-y-1">
                      {processes.length === 0 && <p className="text-xs text-slate-400 text-center py-4 italic">Sin elementos</p>}
                      {processes.map(proc => (
                          <div 
                            key={proc} 
                            onClick={() => setSelectedProcess(proc)}
                            className={`flex items-center justify-between p-2 rounded-lg cursor-pointer text-sm transition-colors group
                                ${selectedProcess === proc ? 'bg-purple-50 text-purple-700 font-bold' : 'text-slate-600 hover:bg-slate-50'}`}
                          >
                              <div className="flex items-center gap-2 truncate">
                                  <Layers size={16} className={selectedProcess === proc ? 'text-purple-500' : 'text-slate-400'} />
                                  <span className="truncate">{proc}</span>
                              </div>
                              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                  <button onClick={(e) => { e.stopPropagation(); handleRenameStart('PROCESS', proc); }} className="text-slate-400 hover:text-purple-600 p-1"><Edit size={12}/></button>
                                  {user.role === UserRole.ADMIN && (
                                      <button onClick={(e) => handleDeleteNode('PROCESS', proc, e)} className="text-slate-400 hover:text-red-600 p-1" title="Eliminar Proceso"><Trash2 size={12}/></button>
                                  )}
                              </div>
                          </div>
                      ))}
                  </div>
              </div>

              {/* COLUMN 4: MICROPROCESSES (LEAVES) */}
              <div className={`bg-white rounded-xl shadow-sm border border-slate-200 flex flex-col overflow-hidden ${!selectedProcess ? 'opacity-50 pointer-events-none' : ''}`}>
                  <div className="p-3 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
                      <h3 className="font-bold text-slate-700 text-xs uppercase tracking-wide">Microprocesos</h3>
                      {selectedProcess && <button onClick={() => handleAdd('MICRO')} className="p-1 hover:bg-indigo-100 text-indigo-600 rounded" title="Nuevo Microproceso"><Plus size={16}/></button>}
                  </div>
                  <div className="flex-1 overflow-y-auto p-2 space-y-1">
                      {columnMicros.length === 0 && <p className="text-xs text-slate-400 text-center py-4 italic">Sin elementos</p>}
                      {columnMicros.map(micro => (
                          <div 
                            key={micro.docId} 
                            className={`flex items-center justify-between p-2 rounded-lg text-sm bg-white border group transition-all ${
                                micro.active === false ? 'border-slate-100 bg-slate-50 text-slate-400 italic' : 'border-slate-100 hover:border-slate-300'
                            }`}
                          >
                              <div className="flex items-center gap-2 truncate">
                                  <FileText size={14} className={micro.active === false ? 'text-slate-300' : 'text-slate-400'} />
                                  <span className="truncate font-medium">{micro.name}</span>
                              </div>

                              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                  {/* MOVE BUTTON */}
                                  <button 
                                    onClick={(e) => handleMoveStart(micro, e)}
                                    className="text-slate-400 hover:text-indigo-600 p-1 hover:bg-indigo-50 rounded"
                                    title="Reubicar (Mover)"
                                  >
                                      <FolderInput size={14} />
                                  </button>

                                  {/* TOGGLE ACTIVE BUTTON */}
                                  <button 
                                    onClick={(e) => handleToggleStatus(micro.docId, micro.name, micro.active !== false, e)} 
                                    className={`p-1 rounded transition-colors ${
                                        micro.active === false ? 'text-slate-300 hover:text-green-600 hover:bg-green-50' : 'text-slate-300 hover:text-red-500 hover:bg-red-50'
                                    }`}
                                    title={micro.active === false ? "Reactivar" : "Inactivar"}
                                  >
                                      <Power size={14}/>
                                  </button>

                                  {/* HARD DELETE BUTTON (ADMIN ONLY) */}
                                  {user.role === UserRole.ADMIN && (
                                      <button 
                                          onClick={(e) => handleHardDeleteMicro(micro.docId, micro.name, e)}
                                          className="p-1 rounded text-slate-300 hover:text-red-600 hover:bg-red-50 transition-colors"
                                          title="Eliminar Definitivamente"
                                      >
                                          <Trash2 size={14} />
                                      </button>
                                  )}
                              </div>
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* MODAL ADD */}
      {showAddModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden">
                <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
                    <h3 className="font-bold text-slate-800">Agregar {addLevel}</h3>
                    <button onClick={() => setShowAddModal(false)}><X size={20} className="text-slate-400 hover:text-slate-600"/></button>
                </div>
                <form onSubmit={handleCreateSubmit} className="p-6">
                    <label className="block text-sm font-medium text-slate-700 mb-2">Nombre del {addLevel}</label>
                    <input 
                        autoFocus
                        type="text" 
                        value={newItemName}
                        onChange={(e) => setNewItemName(e.target.value)}
                        className="w-full p-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500"
                        placeholder={`Ingrese nombre para nuevo ${addLevel.toLowerCase()}...`}
                    />
                    <div className="flex justify-end gap-2 mt-6">
                        <button type="button" onClick={() => setShowAddModal(false)} className="px-4 py-2 text-slate-600 hover:bg-slate-50 rounded text-sm">Cancelar</button>
                        <button type="submit" className="px-4 py-2 bg-indigo-600 text-white rounded text-sm font-medium hover:bg-indigo-700">Crear</button>
                    </div>
                </form>
            </div>
          </div>
      )}

      {/* MODAL RENAME */}
      {renameMode && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
            <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden">
                <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
                    <h3 className="font-bold text-slate-800">Renombrar {renameMode.level}</h3>
                    <button onClick={() => setRenameMode(null)}><X size={20} className="text-slate-400 hover:text-slate-600"/></button>
                </div>
                <div className="p-6">
                    <p className="text-xs text-amber-600 bg-amber-50 p-2 rounded mb-4 border border-amber-100">
                        Atención: Esto actualizará todas las referencias en la base de datos.
                    </p>
                    <label className="block text-sm font-medium text-slate-700 mb-2">Nuevo Nombre</label>
                    <input 
                        autoFocus
                        type="text" 
                        value={renameValue}
                        onChange={(e) => setRenameValue(e.target.value)}
                        className="w-full p-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500"
                    />
                    <div className="flex justify-end gap-2 mt-6">
                        <button onClick={() => setRenameMode(null)} className="px-4 py-2 text-slate-600 hover:bg-slate-50 rounded text-sm">Cancelar</button>
                        <button onClick={handleRenameSubmit} className="px-4 py-2 bg-indigo-600 text-white rounded text-sm font-medium hover:bg-indigo-700">Guardar Cambios</button>
                    </div>
                </div>
            </div>
          </div>
      )}

      {/* MODAL MOVE (RELOCATE) */}
      {showMoveModal && moveTarget && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
                  <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
                      <h3 className="font-bold text-slate-800 flex items-center gap-2">
                          <FolderInput size={20} className="text-indigo-600"/>
                          Reubicar Microproceso
                      </h3>
                      <button onClick={() => setShowMoveModal(false)}><X size={20} className="text-slate-400 hover:text-slate-600"/></button>
                  </div>

                  <form onSubmit={handleMoveSubmit} className="p-6">
                      <div className="bg-blue-50 p-3 rounded-lg border border-blue-100 mb-6 text-sm">
                          <span className="text-slate-500">Moviendo:</span> 
                          <span className="font-bold text-slate-800 ml-2">{moveTarget.name}</span>
                          <div className="flex items-center gap-2 mt-2 text-xs text-slate-500">
                              <span>Desde:</span>
                              <span className="bg-white px-2 py-0.5 rounded border">{moveTarget.currentProject}</span>
                              <ChevronRight size={12}/>
                              <span className="bg-white px-2 py-0.5 rounded border">{moveTarget.currentMacro}</span>
                              <ChevronRight size={12}/>
                              <span className="bg-white px-2 py-0.5 rounded border">{moveTarget.currentProcess}</span>
                          </div>
                      </div>

                      <div className="space-y-4">
                          <div>
                              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Proyecto Destino</label>
                              <select 
                                  value={targetProject}
                                  onChange={(e) => {
                                      setTargetProject(e.target.value);
                                      setTargetMacro(''); // Reset downstream
                                      setTargetProcess('');
                                  }}
                                  className="w-full p-2.5 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500"
                              >
                                  {Object.keys(hierarchy).map(p => <option key={p} value={p}>{p}</option>)}
                              </select>
                          </div>

                          <div>
                              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Macroproceso Destino</label>
                              <select 
                                  value={targetMacro}
                                  onChange={(e) => {
                                      setTargetMacro(e.target.value);
                                      setTargetProcess('');
                                  }}
                                  disabled={!targetProject}
                                  className="w-full p-2.5 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 disabled:bg-slate-100 disabled:text-slate-400"
                              >
                                  <option value="">-- Seleccionar --</option>
                                  {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                              </select>
                          </div>

                          <div>
                              <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Proceso Destino</label>
                              <select 
                                  value={targetProcess}
                                  onChange={(e) => setTargetProcess(e.target.value)}
                                  disabled={!targetMacro}
                                  className="w-full p-2.5 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 disabled:bg-slate-100 disabled:text-slate-400"
                              >
                                  <option value="">-- Seleccionar --</option>
                                  {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                              </select>
                          </div>
                      </div>

                      <div className="flex justify-end gap-2 mt-8">
                          <button type="button" onClick={() => setShowMoveModal(false)} className="px-4 py-2 text-slate-600 hover:bg-slate-50 rounded text-sm font-medium">Cancelar</button>
                          <button 
                            type="submit" 
                            disabled={!targetProcess || loading}
                            className="px-4 py-2 bg-indigo-600 text-white rounded text-sm font-medium hover:bg-indigo-700 disabled:opacity-50 flex items-center gap-2"
                          >
                             {loading && <Loader2 size={14} className="animate-spin"/>}
                             Confirmar Reubicación
                          </button>
                      </div>
                  </form>
              </div>
          </div>
      )}

    </div>
  );
};

export default AdminHierarchy;

import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService, HistoryService, normalizeHeader } from '../services/firebaseBackend.ts';
import { Document, User, DocState, FullHierarchy, DocType, UserRole, DocHistory } from '../types.ts';
import { STATE_CONFIG } from '../constants.ts';
import { 
    PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, AreaChart, Area
} from 'recharts';
import { 
    Users, CheckCircle, Clock, FileText, Filter, LayoutDashboard, Briefcase, Loader2, ArrowRight, Target, TrendingUp, AlertTriangle, Activity, ShieldAlert, CalendarDays, ChevronLeft, ChevronRight, ExternalLink, BarChart2, TableProperties, FileSpreadsheet, ZoomIn, ZoomOut, Layers, PlayCircle, FastForward, Info, ShieldCheck, X, FolderTree
} from 'lucide-react';

interface Props {
    user: User;
}

interface ReportDoc extends Document {
    isVirtual?: boolean;
}

interface StuckDoc extends ReportDoc {
    daysStuck: number;
}

const STATE_COLOR_MAP: Record<string, string> = {
    'No Iniciado': '#94a3b8',
    'En Proceso': '#3b82f6',
    'Referente': '#a855f7',
    'Control': '#f97316',
    'Terminados': '#22c55e'
};

const TYPE_COLORS: Record<string, string> = {
    'AS IS': '#3b82f6',
    'FCE': '#f87171',
    'PM': '#facc15',
    'TO BE': '#22c55e'
};

const STUCK_ITEMS_PER_PAGE = 6;

type ChartScale = 'ANNUAL' | 'MONTHLY' | 'WEEKLY';

const Reports: React.FC<Props> = ({ user }) => {
    const navigate = useNavigate();
    const isAnalyst = user.role === UserRole.ANALYST;

    const [realDocs, setRealDocs] = useState<Document[]>([]);
    const [history, setHistory] = useState<DocHistory[]>([]);
    const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);

    const [activeTab, setActiveTab] = useState<'REPORTS' | 'SUMMARY' | 'CLOSURE'>('REPORTS');
    const [chartScale, setChartScale] = useState<ChartScale>('MONTHLY');
    const [cfdRange, setCfdRange] = useState<3 | 6 | 12>(6);

    const [filterProject, setFilterProject] = useState('');
    const [filterAnalyst, setFilterAnalyst] = useState(isAnalyst ? user.id : '');
    const [activeType, setActiveType] = useState<string | null>(null);

    const [microDrillDown, setMicroDrillDown] = useState<{ title: string, color: string, items: {name: string, project: string, ids: string[]}[] } | null>(null);

    const [closureMonth, setClosureMonth] = useState(() => {
        const d = new Date();
        const startLimit = new Date(2025, 11, 1);
        const selected = d > startLimit ? d : startLimit;
        return `${selected.getFullYear()}-${String(selected.getMonth() + 1).padStart(2, '0')}`;
    });
    const [closurePage, setClosurePage] = useState(1);
    const [stuckPage, setStuckPage] = useState(1);

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [d, u, h, hist] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll(),
                HierarchyService.getFullHierarchy(),
                HistoryService.getAll()
            ]);
            setRealDocs(d);
            setUsers(u);
            setHierarchy(h);
            setHistory(hist);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const unifiedData = useMemo(() => {
        if (Object.keys(hierarchy).length === 0) return [];
        const unifiedList: ReportDoc[] = [];
        const realDocMap = new Map<string, Document>();

        realDocs.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        Object.keys(hierarchy).forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    hierarchy[proj][macro][proc].forEach(node => {
                        if (node.active === false) return;
                        const requiredTypes = node.requiredTypes?.length ? node.requiredTypes : ['AS IS', 'FCE', 'PM', 'TO BE'];
                        requiredTypes.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;
                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                unifiedList.push({ 
                                    ...realDoc, 
                                    macroprocess: macro, 
                                    process: proc, 
                                    project: proj, 
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isVirtual: false 
                                });
                            } else {
                                unifiedList.push({ 
                                    id: `virtual-${key}`, 
                                    title: `${node.name} - ${type}`, 
                                    project: proj, 
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name, 
                                    docType: type as DocType, 
                                    state: DocState.NOT_STARTED, 
                                    updatedAt: new Date(0).toISOString(), 
                                    assignees: node.assignees || [], 
                                    isVirtual: true 
                                } as any);
                            }
                        });
                    });
                });
            });
        });
        return unifiedList;
    }, [realDocs, hierarchy]);

    const filteredDocs = useMemo(() => {
        let docs = unifiedData;
        if (filterProject) docs = docs.filter(d => d.project === filterProject);
        if (filterAnalyst) docs = docs.filter(d => d.assignees?.includes(filterAnalyst));
        return docs;
    }, [unifiedData, filterProject, filterAnalyst]);

    // LÓGICA DE AGREGACIÓN DE MICROPROCESOS (Unidad de Negocio)
    const microStats = useMemo(() => {
        const groups: Record<string, { project: string, name: string, states: DocState[], ids: string[] }> = {};

        filteredDocs.forEach(d => {
            const key = `${d.project}|${d.microprocess}`;
            if (!groups[key]) groups[key] = { project: d.project!, name: d.microprocess!, states: [], ids: [] };
            groups[key].states.push(d.state);
            groups[key].ids.push(d.id);
        });

        const stats = {
            total: [] as {name: string, project: string, ids: string[]}[],
            notStarted: [] as {name: string, project: string, ids: string[]}[],
            inProcess: [] as {name: string, project: string, ids: string[]}[],
            referent: [] as {name: string, project: string, ids: string[]}[],
            control: [] as {name: string, project: string, ids: string[]}[],
            finished: [] as {name: string, project: string, ids: string[]}[]
        };

        Object.values(groups).forEach(group => {
            const microItem = { name: group.name, project: group.project, ids: group.ids };
            stats.total.push(microItem);

            // REGLA CRÍTICA: Un microproceso está TERMINADO solo si el 100% de sus documentos requeridos son APPROVED.
            const allApproved = group.states.length > 0 && group.states.every(s => s === DocState.APPROVED);

            const hasControl = group.states.some(s => [DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW].includes(s));
            const hasReferent = group.states.some(s => [DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW].includes(s));
            const hasProgress = group.states.some(s => s !== DocState.NOT_STARTED);

            if (allApproved) {
                stats.finished.push(microItem);
            } else if (hasControl) {
                stats.control.push(microItem);
            } else if (hasReferent) {
                stats.referent.push(microItem);
            } else if (hasProgress) {
                stats.inProcess.push(microItem);
            } else {
                stats.notStarted.push(microItem);
            }
        });
        return stats;
    }, [filteredDocs]);

    const kpis = useMemo(() => {
        const now = new Date().getTime();
        const thirtyDaysMs = 30 * 24 * 60 * 60 * 1000;
        const approved = filteredDocs.filter(d => d.state === DocState.APPROVED);
        const overdueInternal = filteredDocs.filter(d => d.state === DocState.INTERNAL_REVIEW && (now - new Date(d.updatedAt).getTime()) > thirtyDaysMs);
        const overdueReferent = filteredDocs.filter(d => (d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW) && (now - new Date(d.updatedAt).getTime()) > thirtyDaysMs);
        const overdueControl = filteredDocs.filter(d => (d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW) && (now - new Date(d.updatedAt).getTime()) > thirtyDaysMs);

        return { 
            total: filteredDocs.length, 
            totalIds: filteredDocs.map(d => d.id),
            approved: approved.length, 
            approvedIds: approved.map(d => d.id),
            overdueInternalIds: overdueInternal.map(d => d.id),
            overdueReferentIds: overdueReferent.map(d => d.id),
            overdueControlIds: overdueControl.map(d => d.id)
        };
    }, [filteredDocs]);

    const agileFlowStats = useMemo(() => {
        const stats = {
            backlog: { count: 0, ids: [] as string[] },
            development: { count: 0, ids: [] as string[] },
            internalReview: { count: 0, ids: [] as string[] },
            validation: { count: 0, ids: [] as string[] },
            done: { count: 0, ids: [] as string[] }
        };
        filteredDocs.forEach(d => {
            if (d.state === DocState.NOT_STARTED) { stats.backlog.count++; stats.backlog.ids.push(d.id); }
            else if (d.state === DocState.INITIATED || d.state === DocState.IN_PROCESS) { stats.development.count++; stats.development.ids.push(d.id); }
            else if (d.state === DocState.INTERNAL_REVIEW) { stats.internalReview.count++; stats.internalReview.ids.push(d.id); }
            else if ([DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW, DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW].includes(d.state)) { stats.validation.count++; stats.validation.ids.push(d.id); }
            else if (d.state === DocState.APPROVED) { stats.done.count++; stats.done.ids.push(d.id); }
        });
        return stats;
    }, [filteredDocs]);

    // CFD CON CONTEO CORREGIDO PARA ALINEARSE CON KPIs
    const cfdData = useMemo(() => {
        const data: any[] = [];
        const now = new Date();
        const currentMonthIdx = now.getMonth();
        const currentYearIdx = now.getFullYear();

        const historyByDoc: Record<string, DocHistory[]> = {};
        history.forEach(h => {
            if (!historyByDoc[h.documentId]) historyByDoc[h.documentId] = [];
            historyByDoc[h.documentId].push(h);
        });

        for (let i = cfdRange - 1; i >= 0; i--) {
            const targetDate = new Date(now.getFullYear(), now.getMonth() - i, 1);
            const monthLabel = targetDate.toLocaleString('es-ES', { month: 'short' });

            // Determinar si es el periodo actual para forzar coincidencia con KPIs
            const isCurrentPeriod = targetDate.getMonth() === currentMonthIdx && targetDate.getFullYear() === currentYearIdx;

            const endOfMonth = new Date(targetDate.getFullYear(), targetDate.getMonth() + 1, 0, 23, 59, 59);
            const endOfMonthISO = endOfMonth.toISOString();

            let backlog = 0, dev = 0, review = 0, validation = 0, done = 0;

            filteredDocs.forEach(doc => {
                let stateToCount: DocState = DocState.NOT_STARTED;

                if (isCurrentPeriod) {
                    // SI ES EL MES ACTUAL: Usar el estado real para que coincida 1:1 con las fichas superiores
                    stateToCount = doc.state;
                } else if (doc.isVirtual) {
                    // Documentos no iniciados aún en la matriz
                    stateToCount = DocState.NOT_STARTED;
                } else {
                    // SI ES UN MES PASADO: Reconstruir desde historial
                    const docHistory = (historyByDoc[doc.id] || []).filter(h => h.timestamp <= endOfMonthISO);

                    if (docHistory.length > 0) {
                        const latestEntry = docHistory.sort((a, b) => b.timestamp.localeCompare(a.timestamp))[0];
                        stateToCount = latestEntry.newState;
                    } else {
                        // Fallback: Si no hay historial pero el documento se creó ANTES del fin de este mes analizado
                        const createdDate = new Date(doc.createdAt || doc.updatedAt);
                        if (createdDate <= endOfMonth) {
                            // Asumimos que estaba en su estado actual si no hay registros de cambio
                            stateToCount = doc.state;
                        } else {
                            // Si se creó después del mes analizado, era Backlog (No existía aún en el flujo real)
                            stateToCount = DocState.NOT_STARTED;
                        }
                    }
                }

                // Clasificación estricta (igual que en agileFlowStats)
                if (stateToCount === DocState.APPROVED) done++;
                else if ([DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW, DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW].includes(stateToCount)) validation++;
                else if (stateToCount === DocState.INTERNAL_REVIEW) review++;
                else if (stateToCount === DocState.INITIATED || stateToCount === DocState.IN_PROCESS) dev++;
                else backlog++;
            });

            data.push({ 
                month: monthLabel, 
                'Backlog': backlog, 
                'Desarrollo': dev, 
                'Rev. Interna': review, 
                'Validación': validation, 
                'Finalizado': done 
            });
        }
        return data;
    }, [filteredDocs, history, cfdRange]);

    const closureBoardData = useMemo(() => {
        if (!closureMonth || !unifiedData.length) return [];
        const [year, month] = closureMonth.split('-').map(Number);
        const lastDayOfMonth = new Date(year, month, 0, 23, 59, 59).toISOString();
        const historyByDoc: Record<string, DocHistory[]> = {};
        history.forEach(h => { if (!historyByDoc[h.documentId]) historyByDoc[h.documentId] = []; historyByDoc[h.documentId].push(h); });
        const microMap: Record<string, { project: string, macro: string, process: string, micro: string, docs: Record<string, { state: DocState, version: string }> }> = {};
        unifiedData.forEach(d => {
            if (filterProject && d.project !== filterProject) return;
            if (filterAnalyst && !d.assignees?.includes(filterAnalyst)) return;
            const microKey = `${d.project}|${d.macroprocess}|${d.process}|${d.microprocess}`;
            if (!microMap[microKey]) microMap[microKey] = { project: d.project!, macro: d.macroprocess!, process: d.process!, micro: d.microprocess!, docs: {} };
            let stateAtClosure = DocState.NOT_STARTED; let versionAtClosure = '-';
            if (!d.isVirtual) {
                const docHistory = historyByDoc[d.id] || [];
                const lastEntry = docHistory.filter(h => h.timestamp <= lastDayOfMonth).sort((a, b) => b.timestamp.localeCompare(a.timestamp))[0];
                if (lastEntry) { stateAtClosure = lastEntry.newState; versionAtClosure = lastEntry.version || d.version; } 
                else { const docTimestamp = d.updatedAt ? new Date(d.updatedAt).toISOString() : ''; if (docTimestamp && docTimestamp <= lastDayOfMonth) { stateAtClosure = d.state; versionAtClosure = d.version; } }
            }
            if (d.docType) microMap[microKey].docs[d.docType] = { state: stateAtClosure, version: versionAtClosure };
        });
        return Object.values(microMap).sort((a, b) => a.project.localeCompare(b.project) || a.macro.localeCompare(b.macro) || a.process.localeCompare(b.process) || a.micro.localeCompare(b.micro));
    }, [closureMonth, unifiedData, history, filterProject, filterAnalyst]);

    const executiveMetrics = useMemo(() => {
        if (!filteredDocs.length) return { stuckDocs: [] as StuckDoc[] };
        const now = new Date().getTime();
        const historyByDoc: Record<string, DocHistory[]> = {};
        history.forEach(h => { if (!historyByDoc[h.documentId]) historyByDoc[h.documentId] = []; historyByDoc[h.documentId].push(h); });
        const stuckDocsList: StuckDoc[] = [];
        filteredDocs.forEach(d => {
            if (d.state === DocState.APPROVED || d.state === DocState.NOT_STARTED) return;
            const docHistory = historyByDoc[d.id] || [];
            const lastTransition = docHistory.filter(h => h.newState === d.state).sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())[0];
            const stateEntryDate = lastTransition ? new Date(lastTransition.timestamp).getTime() : new Date(d.createdAt).getTime();
            const daysInState = Math.max(0, Math.floor((now - stateEntryDate) / (1000 * 60 * 60 * 24)));
            if (daysInState > 30) stuckDocsList.push({ ...d, daysStuck: daysInState });
        });
        return { stuckDocs: stuckDocsList.sort((a, b) => b.daysStuck - a.daysStuck) };
    }, [history, filteredDocs]);

    const stateData = useMemo(() => {
        const stats = { notStarted: { value: 0, ids: [] as string[] }, inProcess: { value: 0, ids: [] as string[] }, referent: { value: 0, ids: [] as string[] }, control: { value: 0, ids: [] as string[] }, finished: { value: 0, ids: [] as string[] } };
        filteredDocs.forEach(d => {
            if (d.state === DocState.NOT_STARTED) { stats.notStarted.value++; stats.notStarted.ids.push(d.id); }
            else if (d.state === DocState.APPROVED) { stats.finished.value++; stats.finished.ids.push(d.id); }
            else if (d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW) { stats.referent.value++; stats.referent.ids.push(d.id); }
            else if (d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW) { stats.control.value++; stats.control.ids.push(d.id); }
            else { stats.inProcess.value++; stats.inProcess.ids.push(d.id); }
        });
        return [ { name: 'No Iniciado', ...stats.notStarted }, { name: 'En Proceso', ...stats.inProcess }, { name: 'Referente', ...stats.referent }, { name: 'Control', ...stats.control }, { name: 'Terminados', ...stats.finished } ];
    }, [filteredDocs]);

    const analystData = useMemo(() => {
        const stats: Record<string, { assigned: number, approved: number, inProgress: number }> = {};
        filteredDocs.forEach(d => {
            d.assignees?.forEach(uid => {
                if (!stats[uid]) stats[uid] = { assigned: 0, approved: 0, inProgress: 0 };
                stats[uid].assigned++; if (d.state === DocState.APPROVED) stats[uid].approved++; else if (d.state !== DocState.NOT_STARTED) stats[uid].inProgress++;
            });
        });
        return Object.keys(stats).map(uid => { const u = users.find(user => user.id === uid); return { name: u ? (u.nickname || u.name.split(' ')[0]) : 'Desc.', Requeridos: stats[uid].assigned, EnProceso: stats[uid].inProgress, Terminados: stats[uid].approved }; }).sort((a, b) => b.Requeridos - a.Requeridos).slice(0, 10);
    }, [filteredDocs, users]);

    const typeComplianceData = useMemo(() => {
        const types: DocType[] = ['AS IS', 'FCE', 'PM', 'TO BE'];
        return types.map((type) => {
            const docsOfType = filteredDocs.filter(d => d.docType === type);
            const finishedDocs = docsOfType.filter(d => d.state === DocState.APPROVED);
            const percent = docsOfType.length > 0 ? Math.round((finishedDocs.length / docsOfType.length) * 100) : 0;
            return { type, total: docsOfType.length, finished: finishedDocs.length, percent, color: TYPE_COLORS[type], finishedIds: finishedDocs.map(d => d.id), pendingIds: docsOfType.filter(d => d.state !== DocState.APPROVED).map(d => d.id) };
        });
    }, [filteredDocs]);

    const evolutionData = useMemo(() => {
        const monthsNames = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
        const now = new Date();
        const periods: any[] = [];
        if (chartScale === 'ANNUAL') { for (let i = 4; i >= 0; i--) { const year = now.getFullYear() - i; periods.push({ key: year.toString(), label: year.toString(), 'AS IS': 0, 'FCE': 0, 'PM': 0, 'TO BE': 0 }); } } 
        else if (chartScale === 'MONTHLY') { for (let i = 11; i >= 0; i--) { const d = new Date(now.getFullYear(), now.getMonth() - i, 1); const label = `${monthsNames[d.getMonth()]}-${String(d.getFullYear()).slice(-2)}`; const yearMonthKey = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`; periods.push({ key: yearMonthKey, label: label, 'AS IS': 0, 'FCE': 0, 'PM': 0, 'TO BE': 0 }); } } 
        else if (chartScale === 'WEEKLY') { for (let i = 7; i >= 0; i--) { const d = new Date(); d.setDate(d.getDate() - (i * 7)); const weekNum = Math.ceil(d.getDate() / 7); const label = `S${weekNum}-${monthsNames[d.getMonth()]}`; const firstDayOfYear = new Date(d.getFullYear(), 0, 1); const pastDaysOfYear = (d.getTime() - firstDayOfYear.getTime()) / 86400000; const weekOfYear = Math.ceil((pastDaysOfYear + firstDayOfYear.getDay() + 1) / 7); const key = `${d.getFullYear()}-W${weekOfYear}`; periods.push({ key, label, 'AS IS': 0, 'FCE': 0, 'PM': 0, 'TO BE': 0 }); } }
        filteredDocs.filter(d => d.state === DocState.APPROVED).forEach(d => {
            const date = new Date(d.updatedAt); if (isNaN(date.getTime())) return;
            let docKey = ''; if (chartScale === 'ANNUAL') { docKey = date.getFullYear().toString(); } else if (chartScale === 'MONTHLY') { docKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`; } else if (chartScale === 'WEEKLY') { const firstDayOfYear = new Date(date.getFullYear(), 0, 1); const pastDaysOfYear = (date.getTime() - firstDayOfYear.getTime()) / 86400000; const weekOfYear = Math.ceil((pastDaysOfYear + firstDayOfYear.getDay() + 1) / 7); docKey = `${date.getFullYear()}-W${weekOfYear}`; }
            const period = periods.find(p => p.key === docKey); if (period && d.docType) period[d.docType]++;
        });
        return periods;
