import React, { useState, useEffect, useMemo } from 'react';
import { ReferentService, HierarchyService } from '../services/firebaseBackend.ts';
import { Referent, FullHierarchy, ProcessNode, User, UserRole, UserHierarchy } from '../types.ts';
import { 
    UserPlus, Search, Edit, Trash2, X, Save, Building, Mail, Briefcase, 
    Loader2, AlertCircle, FolderTree, Layers, Network, CheckSquare, Square, ChevronRight, Lock
} from 'lucide-react';

interface Props {
    user: User;
}

const AdminReferents: React.FC<Props> = ({ user }) => {
    const [referents, setReferents] = useState<Referent[]>([]);
    const [fullHierarchy, setFullHierarchy] = useState<FullHierarchy>({});
    const [userHierarchy, setUserHierarchy] = useState<UserHierarchy | null>(null);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [showForm, setShowForm] = useState(false);
    const [editingId, setEditingId] = useState<string | null>(null);

    // Form State
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [specialty, setSpecialty] = useState('');
    const [organization, setOrganization] = useState(''); // Representa el Proyecto principal

    // Hierarchy Selection for linking
    const [linkProject, setLinkProject] = useState('');
    const [linkMacro, setLinkMacro] = useState('');
    const [linkProcess, setLinkProcess] = useState('');
    const [linkMicroSearch, setLinkMicroSearch] = useState('');
    const [selectedMicroIds, setSelectedMicroIds] = useState<string[]>([]);

    const isAnalyst = user.role === UserRole.ANALYST;

    useEffect(() => {
        loadData();
    }, [user.id]);

    const loadData = async () => {
        setLoading(true);
        try {
            const [r, fh] = await Promise.all([
                ReferentService.getAll(),
                HierarchyService.getFullHierarchy()
            ]);

            setFullHierarchy(fh);

            if (isAnalyst) {
                const uh = await HierarchyService.getUserHierarchy(user.id);
                setUserHierarchy(uh);

                // Filtramos los referentes para que el analista solo vea los de sus proyectos asignados
                const userProjects = Object.keys(uh);
                setReferents(r.filter(ref => userProjects.includes(ref.organization)));
            } else {
                setReferents(r);
                setUserHierarchy(null);
            }
        } catch (e) { 
            console.error(e); 
        } finally { 
            setLoading(false); 
        }
    };

    const handleEdit = (r: Referent) => {
        setEditingId(r.id);
        setName(r.name);
        setEmail(r.email);
        setSpecialty(r.specialty);
        setOrganization(r.organization);

        // Cargar microprocesos vinculados actualmente
        const linkedIds: string[] = [];
        Object.keys(fullHierarchy).forEach(proj => {
            Object.keys(fullHierarchy[proj]).forEach(macro => {
                Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                    fullHierarchy[proj][macro][proc].forEach(node => {
                        if (node.referentIds?.includes(r.id)) linkedIds.push(node.docId);
                    });
                });
            });
        });
        setSelectedMicroIds(linkedIds);
        setShowForm(true);
    };

    const resetForm = () => {
        setEditingId(null); setName(''); setEmail(''); setSpecialty(''); setOrganization('');
        setLinkProject(''); setLinkMacro(''); setLinkProcess(''); setLinkMicroSearch('');
        setSelectedMicroIds([]);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        // Seguridad extra: Validar que el analista no esté guardando en un proyecto no permitido
        if (isAnalyst && userHierarchy && !Object.keys(userHierarchy).includes(organization)) {
            alert("No tiene permisos para asignar referentes a este proyecto.");
            return;
        }

        const data = { name, email, specialty, organization };
        try {
            let refId = editingId;
            if (editingId) {
                await ReferentService.update(editingId, data);
            } else {
                const newRef = await ReferentService.create(data);
                refId = newRef.id;
            }

            // Actualizar vinculaciones en la matriz
            if (refId) {
                await HierarchyService.updateReferentLinks(refId, selectedMicroIds);
            }

            setShowForm(false);
            resetForm();
            await loadData();
        } catch (e) { alert("Error al guardar"); }
    };

    const handleDelete = async (id: string) => {
        if (!window.confirm("¿Está seguro de eliminar este referente? Se desvinculará de todos los microprocesos.")) return;
        try {
            await ReferentService.delete(id);
            await loadData();
        } catch (e) { alert("Error al eliminar"); }
    };

    // --- FILTRADO DE MICROPROCESOS PARA VINCULACIÓN ---
    const filteredMicros = useMemo(() => {
        let list: { project: string, macro: string, process: string, node: ProcessNode }[] = [];

        // Usamos la jerarquía filtrada si es analista para el buscador de micros
        const sourceHierarchy = (isAnalyst && userHierarchy) ? fullHierarchy : fullHierarchy;

        Object.keys(sourceHierarchy).forEach(proj => {
            // Si es analista, solo mostramos sus proyectos
            if (isAnalyst && userHierarchy && !userHierarchy[proj]) return;

            if (linkProject && proj !== linkProject) return;

            Object.keys(sourceHierarchy[proj]).forEach(macro => {
                if (linkMacro && macro !== linkMacro) return;
                Object.keys(sourceHierarchy[proj][macro]).forEach(proc => {
                    if (linkProcess && proc !== linkProcess) return;
                    sourceHierarchy[proj][macro][proc].forEach(node => {
                        // Si es analista, solo mostramos los micros donde él mismo está asignado
                        if (isAnalyst && userHierarchy && (!userHierarchy[proj][macro] || !userHierarchy[proj][macro][proc] || !userHierarchy[proj][macro][proc].includes(node.name))) {
                            return;
                        }

                        const matchesSearch = !linkMicroSearch || node.name.toLowerCase().includes(linkMicroSearch.toLowerCase());
                        if (matchesSearch) {
                            list.push({ project: proj, macro, process: proc, node });
                        }
                    });
                });
            });
        });
        return list;
    }, [fullHierarchy, userHierarchy, isAnalyst, linkProject, linkMacro, linkProcess, linkMicroSearch]);

    const availableProjects = useMemo(() => {
        if (isAnalyst && userHierarchy) return Object.keys(userHierarchy).sort();
        return Object.keys(fullHierarchy).sort();
    }, [fullHierarchy, userHierarchy, isAnalyst]);

    const availableMacros = linkProject ? Object.keys(fullHierarchy[linkProject] || {}).sort() : [];
    const availableProcesses = (linkProject && linkMacro) ? Object.keys(fullHierarchy[linkProject][linkMacro] || {}).sort() : [];

    const handleToggleMicro = (docId: string) => {
        setSelectedMicroIds(prev => 
            prev.includes(docId) ? prev.filter(id => id !== docId) : [...prev, docId]
        );
    };

    const filteredReferents = referents.filter(r => 
        r.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        r.specialty.toLowerCase().includes(searchTerm.toLowerCase())
    );

    if (loading && referents.length === 0) return <div className="p-8 text-center text-slate-500"><Loader2 className="animate-spin mx-auto mb-2" /> Cargando referentes y permisos...</div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex flex-col md:flex-row justify-between md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900">Mantenedor de Referentes</h1>
                    <p className="text-slate-500">
                        {isAnalyst 
                          ? "Gestión de expertos técnicos para tus proyectos asignados." 
                          : "Gestión global de expertos técnicos y sus asignaciones."}
                    </p>
                </div>
                <button 
                    onClick={() => { resetForm(); setShowForm(true); }}
                    className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-all shadow-md font-medium"
                >
                    <UserPlus size={18} /> Nuevo Referente
                </button>
            </div>

            {isAnalyst && (
                <div className="bg-amber-50 border border-amber-200 p-3 rounded-lg flex items-center gap-3 text-amber-800 text-sm">
                    <Lock size={18} className="text-amber-600 flex-shrink-0" />
                    <span>Como <b>Analista</b>, solo puedes gestionar referentes dentro de los proyectos y procesos que tienes asignados.</span>
                </div>
            )}

            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
                <div className="relative max-w-md">
                    <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                    <input 
                        type="text"
                        placeholder="Buscar referente por nombre o especialidad..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-10 p-2.5 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                    />
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {filteredReferents.map(r => (
                    <div key={r.id} className="bg-white rounded-xl shadow-sm border border-slate-200 p-5 group hover:border-indigo-300 transition-all">
                        <div className="flex justify-between items-start mb-4">
                            <div className="w-12 h-12 rounded-full bg-slate-100 flex items-center justify-center text-indigo-600 font-bold text-lg">
                                {r.name.charAt(0)}
                            </div>
                            <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                <button onClick={() => handleEdit(r)} className="p-1.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded"><Edit size={16}/></button>
                                <button onClick={() => handleDelete(r.id)} className="p-1.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded"><Trash2 size={16}/></button>
                            </div>
                        </div>
                        <h3 className="font-bold text-slate-900 text-lg mb-1">{r.name}</h3>
                        <div className="space-y-2 text-xs text-slate-600">
                            <div className="flex items-center gap-2"><Briefcase size={14} className="text-slate-400" /> {r.specialty}</div>
                            <div className="flex items-center gap-2"><FolderTree size={14} className="text-slate-400" /> Proyecto: {r.organization}</div>
                            <div className="flex items-center gap-2"><Mail size={14} className="text-slate-400" /> {r.email}</div>
                        </div>
                    </div>
                ))}
                {filteredReferents.length === 0 && (
                    <div className="col-span-full py-12 text-center text-slate-400 italic">No se encontraron referentes en tu ámbito de gestión.</div>
                )}
            </div>

            {showForm && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
                    <div className="bg-white rounded-xl shadow-xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col">
                        <div className="p-5 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
                            <h3 className="text-lg font-bold text-slate-800">{editingId ? 'Editar Referente' : 'Nuevo Referente'}</h3>
                            <button onClick={() => setShowForm(false)} className="text-slate-400 hover:text-slate-600"><X size={20} /></button>
                        </div>

                        <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-6 grid grid-cols-1 lg:grid-cols-2 gap-8">
                            {/* SECCIÓN 1: DATOS PERSONALES */}
                            <div className="space-y-4">
                                <h4 className="font-bold text-sm text-slate-700 border-b pb-2 flex items-center gap-2 uppercase tracking-wide">
                                    <Mail size={16} className="text-indigo-600"/> Perfil del Referente
                                </h4>
                                <div>
                                    <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Nombre Completo</label>
                                    <input type="text" value={name} onChange={(e) => setName(e.target.value)} className="w-full p-2.5 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" required />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Correo Electrónico</label>
                                    <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full p-2.5 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" required />
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Especialidad / Cargo</label>
                                        <input type="text" value={specialty} onChange={(e) => setSpecialty(e.target.value)} className="w-full p-2.5 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" required />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Proyecto</label>
                                        <select value={organization} onChange={(e) => setOrganization(e.target.value)} className="w-full p-2.5 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500" required>
                                            <option value="">Seleccione Proyecto</option>
                                            {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                                            {!isAnalyst && <option value="GENERAL">GENERAL</option>}
                                        </select>
                                    </div>
                                </div>
                            </div>

                            {/* SECCIÓN 2: VINCULACIÓN DE MICROPROCESOS CON FILTROS */}
                            <div className="space-y-4 flex flex-col h-full border-l lg:pl-8">
                                <h4 className="font-bold text-sm text-slate-700 border-b pb-2 flex items-center justify-between uppercase tracking-wide">
                                    <div className="flex items-center gap-2"><Network size={16} className="text-indigo-600"/> Vincular a Microprocesos</div>
                                    <span className="text-[10px] bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded">{selectedMicroIds.length} asignados</span>
                                </h4>

                                {/* FILTROS JERÁRQUICOS */}
                                <div className="space-y-2">
                                    <div className="grid grid-cols-3 gap-2">
                                        <div className="space-y-1">
                                            <label className="block text-[10px] font-bold text-slate-400 uppercase">Proyecto</label>
                                            <select value={linkProject} onChange={(e) => { setLinkProject(e.target.value); setLinkMacro(''); setLinkProcess(''); }} className="w-full text-[10px] p-1.5 border border-slate-200 rounded outline-none focus:ring-1 focus:ring-indigo-400">
                                                <option value="">{isAnalyst ? "TUS PROYECTOS" : "TODOS"}</option>
                                                {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                                            </select>
                                        </div>
                                        <div className="space-y-1">
                                            <label className="block text-[10px] font-bold text-slate-400 uppercase">Macroproceso</label>
                                            <select value={linkMacro} onChange={(e) => { setLinkMacro(e.target.value); setLinkProcess(''); }} className="w-full text-[10px] p-1.5 border border-slate-200 rounded outline-none focus:ring-1 focus:ring-indigo-400" disabled={!linkProject}>
                                                <option value="">TODOS</option>
                                                {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                                            </select>
                                        </div>
                                        <div className="space-y-1">
                                            <label className="block text-[10px] font-bold text-slate-400 uppercase">Proceso</label>
                                            <select value={linkProcess} onChange={(e) => setLinkProcess(e.target.value)} className="w-full text-[10px] p-1.5 border border-slate-200 rounded outline-none focus:ring-1 focus:ring-indigo-400" disabled={!linkMacro}>
                                                <option value="">TODOS</option>
                                                {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                                            </select>
                                        </div>
                                    </div>

                                    {/* BUSCADOR DE MICROS */}
                                    <div className="relative">
                                        <Search size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400" />
                                        <input 
                                            type="text" 
                                            placeholder="BUSCAR POR NOMBRE..." 
                                            value={linkMicroSearch}
                                            onChange={(e) => setLinkMicroSearch(e.target.value)}
                                            className="w-full pl-8 pr-3 py-1.5 border border-slate-200 rounded text-xs outline-none focus:ring-1 focus:ring-indigo-400"
                                        />
                                    </div>
                                </div>

                                {/* LISTADO DE MICROPROCESOS PARA SELECCIONAR */}
                                <div className="flex-1 overflow-y-auto border border-slate-200 rounded-lg bg-slate-50 max-h-[250px]">
                                    {filteredMicros.length === 0 ? (
                                        <div className="p-4 text-center text-slate-400 text-xs italic">No se encontraron microprocesos con los filtros actuales.</div>
                                    ) : (
                                        <div className="divide-y divide-slate-100">
                                            {filteredMicros.map(item => (
                                                <label key={item.node.docId} className="flex items-center gap-3 p-2 hover:bg-white cursor-pointer transition-colors group">
                                                    <div className="relative flex items-center">
                                                        <input 
                                                            type="checkbox" 
                                                            checked={selectedMicroIds.includes(item.node.docId)}
                                                            onChange={() => handleToggleMicro(item.node.docId)}
                                                            className="peer h-4 w-4 cursor-pointer appearance-none rounded border border-slate-300 checked:bg-indigo-600 checked:border-indigo-600"
                                                        />
                                                        <CheckSquare className="absolute w-4 h-4 text-white opacity-0 peer-checked:opacity-100 pointer-events-none p-0.5" />
                                                    </div>
                                                    <div className="min-w-0 flex-1">
                                                        <p className="text-xs font-bold text-slate-800 truncate group-hover:text-indigo-600">{item.node.name}</p>
                                                        <p className="text-[9px] text-slate-500 flex items-center gap-1">
                                                            <span className="font-bold">{item.project}</span> <ChevronRight size={8}/> {item.macro} <ChevronRight size={8}/> {item.process}
                                                        </p>
                                                    </div>
                                                </label>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            </div>

                            <div className="lg:col-span-2 flex justify-end pt-4 gap-3 border-t">
                                <button type="button" onClick={() => setShowForm(false)} className="px-4 py-2 text-slate-600 font-medium">Cancelar</button>
                                <button type="submit" className="flex items-center gap-2 px-8 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-bold shadow-md">
                                    <Save size={18} /> {editingId ? 'Guardar Cambios' : 'Vincular y Guardar'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default AdminReferents;

import React, { useEffect, useState, useMemo } from 'react';
import { Link } from 'react-router-dom';
import { DocumentService, HierarchyService } from '../services/firebaseBackend.ts';
import { Document, User, DocState, UserRole, DocType } from '../types.ts';
import { STATE_CONFIG } from '../constants.ts';
import { Filter, ArrowRight, Calendar, ListTodo, Activity, FileText, Search, ArrowUp, ArrowDown, ArrowUpDown, X, AlertTriangle, PlayCircle } from 'lucide-react';

interface Props {
  user: User;
}

type SortOption = 'microprocess' | 'state' | 'updatedAt';

const WorkList: React.FC<Props> = ({ user }) => {
  const [docs, setDocs] = useState<Document[]>([]);
  const [loading, setLoading] = useState(true);

  // Filters & Search State
  const [filterState, setFilterState] = useState('');
  const [searchTerm, setSearchTerm] = useState('');

  // Sorting State
  const [sortConfig, setSortConfig] = useState<{ key: SortOption; direction: 'asc' | 'desc' }>({
    key: 'updatedAt',
    direction: 'desc'
  });

  useEffect(() => {
    loadData();
  }, []);

  const normalize = (str: string | undefined) => {
      if (!str) return '';
      return str.trim().toUpperCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  };

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocsData, hierarchy] = await Promise.all([
            DocumentService.getAll(),
            HierarchyService.getFullHierarchy()
        ]);

        // 1. Map Real Docs for lookup
        const realDocMap = new Map<string, Document>();
        realDocsData.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalize(doc.project)}|${normalize(microName)}|${normalize(docType)}`;

                // Use latest
                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        // 2. Build Work List from Hierarchy (Assignments)
        const myWorkList: Document[] = [];
        const hierarchyKeys = Object.keys(hierarchy);

        const isCoordOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
        const reviewStates = [
            DocState.INTERNAL_REVIEW, 
            DocState.SENT_TO_REFERENT, 
            DocState.REFERENT_REVIEW, 
            DocState.SENT_TO_CONTROL, 
            DocState.CONTROL_REVIEW
        ];

        hierarchyKeys.forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    const nodes = hierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return; 

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalize(proj)}|${normalize(node.name)}|${normalize(type)}`;

                            if (realDocMap.has(key)) {
                                // Exists in DB
                                const realDoc = realDocMap.get(key)!;

                                // LOGIC: Show if assigned OR if it's pending review and I'm a coordinator
                                const isAssigned = node.assignees && node.assignees.includes(user.id);
                                const isPendingReview = isCoordOrAdmin && reviewStates.includes(realDoc.state);

                                if ((isAssigned || isPendingReview) && realDoc.state !== DocState.APPROVED) {
                                    myWorkList.push({
                                        ...realDoc,
                                        macroprocess: macro,
                                        process: proc,
                                        project: proj,
                                        assignees: node.assignees
                                    });
                                }
                            } else {
                                // Virtual (Not Started)
                                // Only show not started if explicitly assigned
                                const isAssigned = node.assignees && node.assignees.includes(user.id);
                                if (isAssigned) {
                                    myWorkList.push({
                                        id: `virtual-${key}-${Date.now()}`,
                                        title: `${node.name} - ${type}`,
                                        description: 'Pendiente de inicio',
                                        project: proj,
                                        macroprocess: macro,
                                        process: proc,
                                        microprocess: node.name,
                                        docType: type as DocType,
                                        authorId: '',
                                        authorName: '',
                                        assignedTo: user.id,
                                        assignees: node.assignees,
                                        state: DocState.NOT_STARTED,
                                        version: '-',
                                        progress: 0,
                                        files: [],
                                        createdAt: new Date().toISOString(),
                                        updatedAt: new Date(0).toISOString(), 
                                        hasPendingRequest: false
                                    });
                                }
                            }
                        });
                    });
                });
            });
        });

        // 3. Add any "Real" documents that might be assigned but outside hierarchy (Orphans)
        realDocMap.forEach((doc) => {
            const isAssigned = doc.assignees && doc.assignees.includes(user.id);
            const isPendingReview = isCoordOrAdmin && reviewStates.includes(doc.state);

            if ((isAssigned || isPendingReview) && doc.state !== DocState.APPROVED) {
                const exists = myWorkList.some(d => d.id === doc.id);
                if (!exists) {
                    myWorkList.push(doc);
                }
            }
        });

        setDocs(myWorkList);

    } catch (error) {
        console.error("Error loading work list:", error);
    } finally {
        setLoading(false);
    }
  };

  // --- SORT HANDLER ---
  const handleSort = (key: SortOption) => {
      let direction: 'asc' | 'desc' = 'asc';
      if (sortConfig.key === key && sortConfig.direction === 'asc') {
          direction = 'desc';
      }
      setSortConfig({ key, direction });
  };

  // --- FILTER & SORT LOGIC ---
  const processedDocs = useMemo(() => {
      let filtered = [...docs];

      if (filterState) {
          filtered = filtered.filter(d => d.state === filterState);
      }

      if (searchTerm) {
          const lowerTerm = searchTerm.toLowerCase();
          filtered = filtered.filter(d => 
              (d.project || '').toLowerCase().includes(lowerTerm) ||
              (d.microprocess || '').toLowerCase().includes(lowerTerm) ||
              (d.title || '').toLowerCase().includes(lowerTerm)
          );
      }

      return filtered.sort((a, b) => {
          const modifier = sortConfig.direction === 'asc' ? 1 : -1;
          switch (sortConfig.key) {
              case 'microprocess': return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
              case 'state': return ((STATE_CONFIG[a.state]?.progress || 0) - (STATE_CONFIG[b.state]?.progress || 0)) * modifier;
              case 'updatedAt': return (new Date(a.updatedAt).getTime() - new Date(b.updatedAt).getTime()) * modifier;
              default: return 0;
          }
      });
  }, [docs, filterState, searchTerm, sortConfig]);

  const SortIcon = ({ column }: { column: SortOption }) => {
      if (sortConfig.key !== column) return <ArrowUpDown size={14} className="text-slate-300 ml-1 opacity-0 group-hover:opacity-100 transition-opacity" />;
      return sortConfig.direction === 'asc' ? <ArrowUp size={14} className="text-indigo-600 ml-1" /> : <ArrowDown size={14} className="text-indigo-600 ml-1" />;
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando lista de trabajo...</div>;

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
            <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                <ListTodo className="text-indigo-600" />
                Lista de Trabajo
            </h1>
            <p className="text-slate-500">
                {user.role === UserRole.ANALYST ? 'Mis asignaciones pendientes.' : 'Revisiones y asignaciones pendientes.'}
            </p>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 border-b border-slate-100 bg-slate-50/50 flex flex-col md:flex-row md:items-center justify-between gap-4">
                <h2 className="font-semibold text-slate-800 flex items-center gap-2">
                    <Activity size={18} className="text-indigo-600" />
                    Mis Pendientes
                </h2>

                <div className="flex flex-col md:flex-row items-center gap-3 w-full md:w-auto">
                    <div className="relative w-full md:w-64">
                        <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            type="text" 
                            placeholder="Buscar..." 
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full pl-9 pr-8 p-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                        />
                        {searchTerm && (
                            <button onClick={() => setSearchTerm('')} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"><X size={14} /></button>
                        )}
                    </div>

                    <div className="relative w-full md:w-48">
                        <select 
                            value={filterState} 
                            onChange={(e) => setFilterState(e.target.value)}
                            className="w-full p-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
                        >
                            <option value="">Todos los estados</option>
                            {Object.entries(STATE_CONFIG).map(([key, value]) => (
                                <option key={key} value={key}>{value.label.split('(')[0]}</option>
                            ))}
                        </select>
                    </div>
                </div>
            </div>

            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                    <thead className="text-xs text-slate-500 uppercase bg-slate-50">
                        <tr>
                            <th className="px-6 py-3 cursor-pointer group" onClick={() => handleSort('microprocess')}>
                                <div className="flex items-center">Microproceso <SortIcon column="microprocess" /></div>
                            </th>
                            <th className="px-6 py-3">Tipo</th>
                            <th className="px-6 py-3 cursor-pointer group" onClick={() => handleSort('state')}>
                                <div className="flex items-center">Estado <SortIcon column="state" /></div>
                            </th>
                            <th className="px-6 py-3 cursor-pointer group text-right" onClick={() => handleSort('updatedAt')}>
                                <div className="flex items-center justify-end">Última Actividad <SortIcon column="updatedAt" /></div>
                            </th>
                            <th className="px-6 py-3"></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                        {processedDocs.length === 0 ? (
                            <tr>
                                <td colSpan={5} className="px-6 py-12 text-center text-slate-400">
                                    <div className="flex flex-col items-center">
                                        <Search size={40} className="mb-2 opacity-20" />
                                        <p>No se encontraron tareas pendientes.</p>
                                    </div>
                                </td>
                            </tr>
                        ) : (
                            processedDocs.map((doc) => (
                                <tr key={doc.id} className="hover:bg-slate-50 transition-colors">
                                    <td className="px-6 py-4">
                                        <div className="font-medium text-slate-900">{doc.microprocess || doc.title}</div>
                                        <div className="text-xs text-slate-500">{doc.project} • {doc.process}</div>
                                    </td>
                                    <td className="px-6 py-4">
                                        <span className="px-2 py-0.5 rounded bg-indigo-50 text-indigo-700 text-[10px] font-bold border border-indigo-100">
                                            {doc.docType}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4">
                                        <div className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border ${STATE_CONFIG[doc.state].color}`}>
                                            {STATE_CONFIG[doc.state].label.split('(')[0]}
                                        </div>
                                        <div className="text-[10px] text-slate-400 mt-1">{doc.version}</div>
                                    </td>
                                    <td className="px-6 py-4 text-right text-slate-500">
                                        {doc.state !== DocState.NOT_STARTED ? new Date(doc.updatedAt).toLocaleDateString() : '-'}
                                    </td>
                                    <td className="px-6 py-4 text-right">
                                        <Link 
                                            to={`/doc/${doc.id}`} 
                                            state={{ docData: doc }}
                                            className="inline-flex items-center text-indigo-600 hover:text-indigo-900 font-medium"
                                        >
                                            Gestionar <ArrowRight size={16} className="ml-1" />
                                        </Link>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>
      </div>
    </div>
  );
};

export default WorkList;
